    <script type="text/javascript" >
// Hàm trợ giúp để lấy nội dung system_data từ nguồn dữ liệu XML
function getSystemDataFromXml() {
  const systemDataXmlElement = document.getElementById('system_data_xml');
  if (!systemDataXmlElement) {
    console.warn('Không tìm thấy nguồn dữ liệu system_data_xml');
    return null;
  }

  try {
    // Phân tích cú pháp dữ liệu XML
    const parser = new DOMParser();
    const xmlDoc = parser.parseFromString(systemDataXmlElement.textContent, 'text/xml');

    // Lấy nội dung của thẻ system_data
    const systemDataNode = xmlDoc.querySelector('system_data');

    if (systemDataNode) {
      return systemDataNode.textContent.trim();
    } else {
      console.warn('Không tìm thấy thẻ system_data trong dữ liệu XML');
      return null;
    }
  } catch (e) {
    console.error('Phân tích cú pháp system_data trong XML thất bại:', e);
    return null;
  }
}

// Hiển thị nội dung maintext vào khu vực story-text-content
function renderMainText() {
  const systemDataXmlElement = document.getElementById('system_data_xml');
  const storyContentElement = document.getElementById('story-text-content');

  if (systemDataXmlElement && storyContentElement) {
    try {
      // Phân tích cú pháp dữ liệu XML
      const parser = new DOMParser();
      const xmlDoc = parser.parseFromString(systemDataXmlElement.textContent, 'text/xml');

      // Lấy nội dung của thẻ maintext
      const mainTextNode = xmlDoc.querySelector('maintext');

      if (mainTextNode) {
        const mainTextContent = mainTextNode.textContent.trim();

        if (mainTextContent) {
          // Tách văn bản theo đoạn và hiển thị, nhưng không thêm định dạng khác
          const paragraphs = mainTextContent.split(/\n\s*\n/);
          let htmlContent = '';

          paragraphs.forEach(paragraph => {
            if (paragraph.trim()) {
              htmlContent += `<p class="mb-4">${paragraph.trim()}</p>`;
            }
          });

          storyContentElement.innerHTML = htmlContent;
          console.log('Nội dung MainText đã được hiển thị từ nguồn dữ liệu XML vào khu vực câu chuyện');
        } else {
          console.warn('Thẻ maintext trong XML trống');
        }
      } else {
        console.warn('Không tìm thấy thẻ maintext trong dữ liệu XML');
      }
    } catch (e) {
      console.error('Phân tích cú pháp dữ liệu XML thất bại:', e);
    }
  } else {
    console.warn('Không tìm thấy phần tử system_data_xml hoặc story-text-content');
  }
}

// Quản lý trạng thái trò chơi
const gameState = {
  currentMode: 'action_selection_mode', // Chế độ chơi hiện tại (key tiếng Anh)
  currentAction: 'Trạng thái chờ chọn', // Trạng thái hành động hiện tại
  pendingSettlementAction: '', // Văn bản hành động thanh toán chiến đấu đang chờ gửi
  modeMapping: null, // Mối quan hệ ánh xạ chế độ

  // Khởi tạo ánh xạ chế độ
  initModeMapping: function() {
    try {
      const modeElement = document.getElementById('mode_action_relationships');
      if (modeElement) {
        this.modeMapping = JSON.parse(modeElement.textContent);
      }
    } catch (e) {
      console.error('Không thể phân tích cú pháp dữ liệu mode_action_relationships:', e);
      // Cung cấp ánh xạ mặc định làm dự phòng
      this.modeMapping = {
        "action_selection_mode": {
          "name": "Chế độ lựa chọn hành động",
          "actions": ["Trạng thái chờ chọn", "Mở cửa phòng"]
        },
        "battle_mode": {
          "name": "Chế độ chiến đấu",
          "actions": ["Trạng thái trước chiến đấu", "Trạng thái đang chiến đấu", "Kết thúc chiến đấu", "Hành động lựa chọn sau khi chiến thắng", "Chạy trốn"]
        },
        "sex_mode": {
          "name": "Chế độ tình dục",
          "actions": ["Bắt đầu quan hệ tình dục", "Đang quan hệ tình dục", "Kết thúc quan hệ tình dục"]
        },
        "battle_settlement_mode": {
          "name": "Chế độ thanh toán chiến đấu",
          "actions": ["Bắt đầu thanh toán", "Đang xác nhận thanh toán", "Kết thúc thanh toán"]
        },
        "game_failure_state": {
          "name": "Chế độ thất bại",
          "actions": ["Hiển thị giao diện thất bại"]
        },
        "game_victory_state": {
          "name": "Chế độ chiến thắng",
          "actions": ["Hiển thị giao diện chiến thắng"]
        }
      };
    }
  },

  // Đọc chế độ hiện tại từ system_data_xml
  loadCurrentModeFromData: function() {
    try {
      const systemDataYaml = getSystemDataFromXml();
      if (!systemDataYaml) {
        console.warn('Không tìm thấy nguồn dữ liệu system_data_xml');
        return;
      }

      const data = jsyaml.load(systemDataYaml);
      const systemData = data.system_data?.system;

      if (systemData && systemData.state) {
        const newMode = systemData.state;
        const newAction = systemData.action || 'Trạng thái chờ chọn';

        // Chỉ cập nhật khi chế độ thực sự thay đổi
        if (this.currentMode !== newMode || this.currentAction !== newAction) {
          console.log('Phát hiện thay đổi chế độ:', this.currentMode, '->', newMode, 'Hành động:', this.currentAction, '->', newAction);
          this.currentMode = newMode;
          this.currentAction = newAction;
          this.updateStateDisplay();
          this.updateOptionsDisplay();
        } else {
          console.log('Chế độ không đổi, chế độ hiện tại:', this.currentMode, 'Hành động:', this.currentAction);
        }
      }
    } catch (e) {
      console.error('Đọc chế độ từ system_data_xml thất bại:', e);
    }
  },

  // Lấy tên hiển thị tiếng Việt của chế độ
  getModeName: function(modeKey) {
    if (!this.modeMapping) {
      this.initModeMapping();
    }
    return this.modeMapping[modeKey]?.name || modeKey;
  },

  // Lấy danh sách hành động khả dụng của chế độ
  getModeActions: function(modeKey) {
    if (!this.modeMapping) {
      this.initModeMapping();
    }
    return this.modeMapping[modeKey]?.actions || [];
  },

  // Đặt chế độ và hành động của trò chơi
  setModeAndAction: function (mode, action) {
    this.currentMode = mode;
    this.currentAction = action;
    this.updateStateDisplay();
    this.updateOptionsDisplay();
  },

  // Cập nhật hiển thị trạng thái
  updateStateDisplay: function () {
    // Đã xóa cập nhật status-indicator vì phần tử đó đã bị xóa
    console.log('Chế độ hiện tại:', this.getModeName(this.currentMode), 'Hành động hiện tại:', this.currentAction);
  },

  // Cập nhật hiển thị tùy chọn
  updateOptionsDisplay: function () {
    console.log('updateOptionsDisplay được gọi, chế độ hiện tại:', this.currentMode, 'Hành động hiện tại:', this.currentAction);
    const actionSection = document.getElementById('action-section');
    const locationSection = document.getElementById('location-section');
    const battleSection = document.getElementById('battle-section');
    const sexSection = document.getElementById('sex-section');
    const battleSettlementModal = document.getElementById('battle-settlement-modal');
    const gameFailureModal = document.getElementById('game-failure-modal');
    const gameVictoryModal = document.getElementById('game-victory-modal');

    // Ẩn tất cả các khu vực và cửa sổ bật lên
    actionSection.classList.add('hidden-section');
    locationSection.classList.add('hidden-section');
    battleSection.classList.add('hidden-section');
    sexSection.classList.add('hidden-section');

    // Ẩn tất cả các cửa sổ bật lên
    if (battleSettlementModal) {
      battleSettlementModal.classList.add('hidden');
      battleSettlementModal.style.display = 'none';
    }
    if (gameFailureModal) {
      gameFailureModal.classList.add('hidden');
      gameFailureModal.style.display = 'none';
    }
    if (gameVictoryModal) {
      gameVictoryModal.classList.add('hidden');
      gameVictoryModal.style.display = 'none';
    }

    // Hiển thị khu vực tương ứng theo chế độ hiện tại
    switch (this.currentMode) {
      case 'action_selection_mode':
        // action_selection_mode - Hiển thị khu vực hộp chọn di chuyển vị trí
        console.log('Hiển thị hộp chọn di chuyển vị trí, hành động hiện tại:', this.currentAction);
        if (locationSection) {
          locationSection.classList.remove('hidden-section');
          console.log('Lớp location-section hidden-section đã được xóa, danh sách lớp hiện tại:', locationSection.className);
        } else {
          console.error('Không tìm thấy phần tử location-section!');
        }
        break;
      case 'battle_mode':
        // battle_mode - Hiển thị tùy chọn chiến đấu
        battleSection.classList.remove('hidden-section');
        this.generateBattleOptions();
        break;
      case 'sex_mode':
        // sex_mode - Hiển thị tùy chọn tình dục
        sexSection.classList.remove('hidden-section');
        this.generateSexOptions();
        break;
      case 'battle_settlement_mode':
        // battle_settlement_mode - Hiển thị nội dung thanh toán chiến đấu trong khu vực lựa chọn hành động
        actionSection.classList.remove('hidden-section');
        this.generateBattleSettlementOptions();
        break;
      case 'game_failure_state':
        // game_failure_state - Hiển thị cửa sổ bật lên khi thua game
        this.showGameFailureModal();
        break;
      case 'game_victory_state':
        // game_victory_state - Hiển thị cửa sổ bật lên khi thắng game
        this.showGameVictoryModal();
        break;
      default:
        // Theo mặc định, không hiển thị bất kỳ khu vực nội dung đặc biệt nào
        // Tất cả các khu vực đều được giữ ở trạng thái ẩn
        console.log('Chế độ không xác định:', this.currentMode);
    }

    // Logic tự động thu gọn bảng thông tin
    this.handleSmartCollapse();
  },

  // Xử lý tự động thu gọn bảng thông tin
  handleSmartCollapse: function () {
    // Lấy cài đặt tự động thu gọn
    const savedSettings = localStorage.getItem('gameSettings');
    let smartCollapseEnabled = true; // Bật theo mặc định

    if (savedSettings) {
      try {
        const settings = JSON.parse(savedSettings);
        smartCollapseEnabled = settings.smartCollapse !== 'disabled';
      } catch (e) {
        console.error('Đọc cài đặt tự động thu gọn thất bại:', e);
      }
    }

    // Nếu tự động thu gọn bị tắt, trả về trực tiếp
    if (!smartCollapseEnabled) {
      return;
    }

    const infoPanelContent = document.getElementById('info-panel-content');
    const infoPanelIcon = document.getElementById('info-panel-icon');

    if (!infoPanelContent || !infoPanelIcon) {
      return;
    }

    // Mở rộng bảng thông tin trong chế độ chiến đấu, thu gọn trong các chế độ khác
    if (this.currentMode === 'battle_mode') {
      // Mở rộng bảng thông tin
      infoPanelContent.classList.remove('collapsible-collapsed');
      infoPanelContent.classList.add('collapsible-expanded');
      infoPanelIcon.style.transform = 'rotate(180deg)';
    } else {
      // Thu gọn bảng thông tin
      infoPanelContent.classList.remove('collapsible-expanded');
      infoPanelContent.classList.add('collapsible-collapsed');
      infoPanelIcon.style.transform = 'rotate(0deg)';
    }
  },

  // Tạo tùy chọn lựa chọn hành động
  generateActionSelectionOptions: function () {
    const actionSection = document.getElementById('action-section');
    actionSection.innerHTML = ''; // Xóa các tùy chọn hiện có

    // Tạo tùy chọn dựa trên trạng thái hành động hiện tại
    if (this.currentAction === 'Trạng thái chờ chọn') {
      // Hiển thị các tùy chọn hành động cơ bản trong trạng thái chờ chọn
      const actionHTML = `
        <div class="text-center">
          <p class="text-gray-600 mb-4">Vui lòng chọn hành động của bạn hoặc chọn di chuyển vị trí</p>
          <div class="space-y-2">
            <button class="w-full bg-primary hover:bg-primary/80 text-white py-2 px-4 rounded-lg transition-all duration-300 font-medium action-selection-btn" 
                    data-action="Xem xét môi trường xung quanh">
              <i class="fa fa-search mr-2"></i>Xem xét môi trường xung quanh
            </button>
            <button class="w-full bg-secondary hover:bg-secondary/80 text-white py-2 px-4 rounded-lg transition-all duration-300 font-medium action-selection-btn" 
                    data-action="Nghỉ ngơi phục hồi">
              <i class="fa fa-bed mr-2"></i>Nghỉ ngơi phục hồi
            </button>
          </div>
        </div>
      `;
      actionSection.innerHTML = actionHTML;
    }
  },

  // Xử lý lựa chọn hành động
  handleActionSelection: function (action) {
    console.log('Hành động đã chọn:', action);
    // Ở đây có thể thực hiện các logic khác nhau dựa trên các hành động khác nhau
    // Tạm thời chỉ ghi lại nhật ký
  },

  // Tạo tùy chọn chiến đấu
  generateBattleOptions: function () {
    const battleOptionsContainer = document.getElementById('battle-options');
    battleOptionsContainer.innerHTML = ''; // Xóa các tùy chọn hiện có

    // Kiểm tra xem có phải là "Trạng thái trước chiến đấu" không
    if (this.currentAction === 'Trạng thái trước chiến đấu') {
      // Hai tùy chọn cố định trước trận chiến
      const battleButton = document.createElement('button');
      battleButton.className = 'compact-battle-btn';
      battleButton.innerHTML = `<i class="fa fa-sword mr-2"></i>Tôi biết trận chiến là không thể tránh khỏi, tôi tấn công cô ấy.`;
      // Xóa onclick, sử dụng trình lắng nghe ủy quyền sự kiện để xử lý
      battleOptionsContainer.appendChild(battleButton);

      const runButton = document.createElement('button');
      runButton.className = 'compact-battle-run-btn';
      const runSentence = this.getRandomSentence('run_away_sentences');
      runButton.innerHTML = `<i class="fa fa-running mr-2"></i>${runSentence}`;
      // Xóa onclick, sử dụng trình lắng nghe ủy quyền sự kiện để xử lý
      battleOptionsContainer.appendChild(runButton);

      return; // Chỉ hiển thị hai tùy chọn này trong trạng thái trước trận chiến, không hiển thị các tùy chọn khác
    }

    // Kiểm tra xem có phải là trạng thái "Lựa chọn sau khi chiến thắng" không
    if (this.currentAction === 'Hành động lựa chọn sau khi chiến thắng') {
      // Hai tùy chọn cố định sau khi chiến thắng
      const acceptButton = document.createElement('button');
      acceptButton.className = 'compact-battle-btn';
      acceptButton.innerHTML = `<i class="fa fa-heart mr-2"></i>Tôi nhận thấy thể lực hiện tại của mình không đủ, dáng vẻ hiện tại của cô ấy khiến tôi thương cảm, tôi chấp nhận lời mời quan hệ của cô ấy.`;
      // Xóa onclick, sử dụng trình lắng nghe ủy quyền sự kiện để xử lý
      battleOptionsContainer.appendChild(acceptButton);

      const rejectButton = document.createElement('button');
      rejectButton.className = 'compact-battle-btn';
      rejectButton.innerHTML = `<i class="fa fa-shield mr-2"></i>Tôi cảm thấy thể lực của mình vẫn còn dồi dào, cô ấy chỉ hơi lo lắng cho tôi thôi. Tôi từ chối đề nghị của cô ấy.`;
      // Xóa onclick, sử dụng trình lắng nghe ủy quyền sự kiện để xử lý
      battleOptionsContainer.appendChild(rejectButton);

      return; // Chỉ hiển thị hai tùy chọn này khi lựa chọn sau khi chiến thắng, không hiển thị các tùy chọn khác
    }

    // Lấy options từ nguồn dữ liệu YAML
    let backendOptions = ['Trận chiến không thể tránh khỏi, tôi phải chiến đấu, tôi tấn công cô ấy']; // Tùy chọn mặc định
    try {
      const systemDataYaml = getSystemDataFromXml();
      if (systemDataYaml) {
        const data = jsyaml.load(systemDataYaml);
        const options = data.system_data?.options;
        if (options && Array.isArray(options) && options.length > 0) {
          backendOptions = options;
        }
      }
    } catch (e) {
      console.warn('Không thể lấy dữ liệu options, sử dụng tùy chọn mặc định:', e);
    }

    // Thêm tùy chọn từ backend
    backendOptions.forEach((option, index) => {
      const button = document.createElement('button');
      button.className = 'compact-battle-btn';
      button.innerHTML = `<i class="fa fa-sword mr-2"></i>${option}`;
      // Xóa onclick, sử dụng trình lắng nghe ủy quyền sự kiện để xử lý
      battleOptionsContainer.appendChild(button);
    });

    // Nếu là trạng thái đang chiến đấu, thêm hai tùy chọn cố định
    if (this.currentAction === 'Vào trạng thái đang chiến đấu' || this.currentAction === 'Trạng thái đang chiến đấu') {
      // Tùy chọn tiếp tục chiến đấu
      const continueButton = document.createElement('button');
      continueButton.className = 'compact-battle-continue-btn';
      const battleSentence = this.getRandomSentence('battle_sentences');
      continueButton.innerHTML = `<i class="fa fa-fist-raised mr-2"></i>${battleSentence}`;
      // Xóa onclick, sử dụng trình lắng nghe ủy quyền sự kiện để xử lý
      battleOptionsContainer.appendChild(continueButton);

      // Tùy chọn chạy trốn
      const runButton = document.createElement('button');
      runButton.className = 'compact-battle-run-btn';
      const runSentence = this.getRandomSentence('run_away_sentences');
      runButton.innerHTML = `<i class="fa fa-running mr-2"></i>${runSentence}`;
      // Xóa onclick, sử dụng trình lắng nghe ủy quyền sự kiện để xử lý
      battleOptionsContainer.appendChild(runButton);
    }
  },

  // Tạo tùy chọn tình dục
  generateSexOptions: function () {
    const sexOptionsContainer = document.getElementById('sex-options');
    sexOptionsContainer.innerHTML = ''; // Xóa các tùy chọn hiện có

    // Lấy options từ nguồn dữ liệu YAML
    let backendOptions = ['Vuốt ve nhẹ nhàng', 'Hôn nồng cháy', 'Âu yếm dịu dàng']; // Tùy chọn mặc định
    try {
      const systemDataYaml = getSystemDataFromXml();
      if (systemDataYaml) {
        const data = jsyaml.load(systemDataYaml);
        const options = data.system_data?.options;
        if (options && Array.isArray(options) && options.length > 0) {
          backendOptions = options;
        }
      }
    } catch (e) {
      console.warn('Không thể lấy dữ liệu options, sử dụng tùy chọn mặc định:', e);
    }

    // Thêm tùy chọn từ backend
    backendOptions.forEach((option, index) => {
      const button = document.createElement('button');
      button.className = 'compact-sex-btn';
      button.innerHTML = `<i class="fa fa-heart mr-2"></i>${option}`;
      button.onclick = () => this.handleSexAction(option);
      sexOptionsContainer.appendChild(button);
    });

    // Nếu là trạng thái đang quan hệ tình dục, thêm hai tùy chọn cố định
    if (this.currentAction === 'Bắt đầu quan hệ tình dục' || this.currentAction === 'Đang quan hệ tình dục') {
      // Tùy chọn tiếp tục quan hệ tình dục
      const continueButton = document.createElement('button');
      continueButton.className = 'compact-sex-continue-btn';
      const sexSentence = this.getRandomSentence('dialogues_sentences');
      continueButton.innerHTML = `<i class="fa fa-heart mr-2"></i>${sexSentence}`;
      continueButton.onclick = () => this.handleSexAction('Tiếp tục làm tình');
      sexOptionsContainer.appendChild(continueButton);

      // Tùy chọn kết thúc quan hệ tình dục
      const endButton = document.createElement('button');
      endButton.className = 'compact-sex-end-btn';
      endButton.innerHTML = `<i class="fa fa-stop mr-2"></i>Kết thúc quan hệ tình dục:Bạn muốn xuất tinh ngay lập tức để kết thúc cuộc làm tình này.`;
      endButton.onclick = () => this.handleSexAction('Kết thúc làm tình');
      sexOptionsContainer.appendChild(endButton);
