  // Lấy thông tin trang bị hiện tại
  getCurrentEquipment: function () {
    try {
      const systemDataYaml = getSystemDataFromXml();
      if (!systemDataYaml) return null;

      const data = jsyaml.load(systemDataYaml);
      return data.system_data?.user?.equipped_equipment || null;
    } catch (e) {
      console.error('Lấy thông tin trang bị hiện tại thất bại:', e);
      return null;
    }
  },

  // Chức năng so sánh trang bị
  compareEquipment: function (currentEquipment, newEquipment) {
    const currentAttack = (currentEquipment && currentEquipment.attack_bonus) || 0;
    const currentDefense = (currentEquipment && currentEquipment.defense_bonus) || 0;
    const newAttack = newEquipment.attack_bonus || 0;
    const newDefense = newEquipment.defense_bonus || 0;

    return {
      attack: {
        current: currentAttack,
        new: newAttack,
        change: newAttack - currentAttack,
      },
      defense: {
        current: currentDefense,
        new: newDefense,
        change: newDefense - currentDefense,
      },
    };
  },

  // Lấy biểu tượng trang bị
  getEquipmentIcon: function (type) {
    const iconMap = {
      weapon: 'fa-sword',
      armor: 'fa-shield-alt',
      accessory: 'fa-gem',
      consumable: 'fa-flask',
      default: 'fa-box',
    };
    return iconMap[type] || iconMap['default'];
  },

