  showGameFailureModal: function () {
    const modal = document.getElementById('game-failure-modal');
    if (modal) {
      modal.classList.remove('hidden');
      modal.style.display = 'flex';
    }
  },

  // Hiển thị cửa sổ bật lên khi thắng game
  showGameVictoryModal: function () {
    const modal = document.getElementById('game-victory-modal');
    if (modal) {
      modal.classList.remove('hidden');
      modal.style.display = 'flex';
    }
  },

  // Lấy câu ngẫu nhiên
  getRandomSentence: function (dataSourceId) {
    try {
      const dataElement = document.getElementById(dataSourceId);
      if (!dataElement) return 'Văn bản mặc định';

      const data = JSON.parse(dataElement.textContent);
      let sentences = [];

      if (dataSourceId === 'battle_sentences') {
        sentences = data.battle_sentences || [];
      } else if (dataSourceId === 'run_away_sentences') {
        sentences = data.run_away_sentences || [];
      } else if (dataSourceId === 'dialogues_sentences') {
        sentences = data.dialogues_sentences || [];
      }

      if (sentences.length === 0) return 'Văn bản mặc định';

      const randomIndex = Math.floor(Math.random() * sentences.length);
      return sentences[randomIndex];
    } catch (e) {
      console.error('Lấy câu ngẫu nhiên thất bại:', e);
      return 'Văn bản mặc định';
    }
  },

  // Xử lý hành động chiến đấu
  handleBattleAction: function (action) {
    console.log('Thực hiện hành động chiến đấu:', action, 'Trạng thái hiện tại:', this.currentAction);

    // Phán đoán xem có cần gọi hệ thống chiến đấu và bao gồm dữ liệu battle không
    const needsBattleSystem = (
      action !== 'Chạy trốn' && 
      this.currentAction !== 'Hành động lựa chọn sau khi chiến thắng' &&
      (this.currentAction === 'Trạng thái trước chiến đấu' || this.currentAction === 'Trạng thái đang chiến đấu')
    );

    // Nếu cần, gọi hệ thống chiến đấu theo lượt
    if (needsBattleSystem) {
      initiateTurnBasedBattle();
    }

    // Dựa vào trạng thái để quyết định có bao gồm dữ liệu battle_process không
    let fullText;
    if (needsBattleSystem) {
      // Trạng thái trước chiến đấu và trạng thái đang chiến đấu (không phải chạy trốn): bao gồm dữ liệu battle
      const battleProcessText = getBattleProcessText();
      fullText = `${action}\n\n${battleProcessText}`;
    } else {
      // Lựa chọn sau khi chiến thắng hoặc chạy trốn: chỉ gửi văn bản hành động
      fullText = action;
    }

    // Gửi tin nhắn đầy đủ - thông qua hàm triggerQuickReply toàn cục
    if (typeof window.triggerQuickReply === 'function') {
      window.triggerQuickReply(fullText);
    } else {
      console.error('Hàm triggerQuickReply không khả dụng');
      console.log('Tin nhắn cần gửi:', fullText);
    }
  },

  // Xử lý hành động tình dục
  handleSexAction: function (action) {
    // TODO: Triển khai logic hành động tình dục
  },

