    // Xóa trình lắng nghe định kỳ, chỉ khởi tạo một lần khi bắt đầu
    console.log('Khởi tạo trạng thái trò chơi hoàn tất, chế độ hiện tại:', this.currentMode, 'Hành động:', this.currentAction);
  },
};

// Chức năng thu gọn bảng thông tin - khi nhấp sẽ thu gọn toàn bộ thông tin cá nhân và thông tin kẻ địch
function setupInfoPanelToggle() {
  const toggle = document.getElementById('info-panel-toggle');
  const content = document.getElementById('info-panel-content');
  const icon = document.getElementById('info-panel-icon');

  toggle.addEventListener('click', function () {
    // Chuyển đổi trạng thái mở rộng/thu gọn của toàn bộ khu vực nội dung
    const isExpanded = content.classList.contains('collapsible-expanded');

    if (isExpanded) {
      // Thu gọn: xóa lớp expanded trước, kích hoạt hoạt ảnh thu lại
      content.classList.remove('collapsible-expanded');
      icon.style.transform = 'rotate(0deg)';
    } else {
      // Mở rộng: thêm lớp expanded, kích hoạt hoạt ảnh mở ra
      content.classList.add('collapsible-expanded');
      icon.style.transform = 'rotate(180deg)';
    }
  });
}

// Chức năng chuyển đổi Tab
function setupTabSwitching() {
  const storyBtn = document.getElementById('tab-story-btn');
  const battleBtn = document.getElementById('tab-battle-btn');
  const storyContent = document.getElementById('tab-story-content');
  const battleContent = document.getElementById('tab-battle-content');

  // Chuyển sang Tab Nội dung chính
  function switchToStoryTab() {
    // Cập nhật trạng thái nút
    storyBtn.classList.add('active');
    battleBtn.classList.remove('active');

    // Cập nhật hiển thị nội dung
    storyContent.classList.add('active');
    battleContent.classList.remove('active');
  }

  // Chuyển sang Tab Quá trình chiến đấu
  function switchToBattleTab() {
    // Cập nhật trạng thái nút
    battleBtn.classList.add('active');
    storyBtn.classList.remove('active');

    // Cập nhật hiển thị nội dung
    battleContent.classList.add('active');
    storyContent.classList.remove('active');
  }

  // Gán sự kiện nhấp chuột
  storyBtn.addEventListener('click', switchToStoryTab);
  battleBtn.addEventListener('click', switchToBattleTab);

  // Mặc định hiển thị Tab Nội dung chính (đã đặt lớp active trong HTML)
}

// Chức năng hiển thị trạng thái hệ thống
function setupSystemStatusDisplay() {
  // Phân tích cú pháp dữ liệu trạng thái hệ thống
  function parseSystemStatusData() {
    const systemDataYaml = getSystemDataFromXml();
    if (!systemDataYaml) {
      console.error('Không tìm thấy nguồn dữ liệu system_data_xml');
      return null;
    }

    try {
      const data = jsyaml.load(systemDataYaml);
      return data.system_data?.system || null;
    } catch (e) {
      console.error('Phân tích cú pháp dữ liệu trạng thái hệ thống thất bại:', e);
      return null;
    }
  }

  // Cập nhật hiển thị trạng thái
  function updateStatusDisplay() {
    const systemData = parseSystemStatusData();

    // Lấy phần tử hiển thị
    const currentMode = document.getElementById('current-mode');
    const currentAction = document.getElementById('current-action');
    const currentFloor = document.getElementById('current-floor');
    const currentRoom = document.getElementById('current-room');

    if (systemData) {
      // Cập nhật chế độ hiện tại - chuyển đổi trạng thái tiếng Anh sang hiển thị tiếng Việt
      if (currentMode) {
        const stateKey = systemData.state;
        const chineseName = gameState.getModeName(stateKey);
        currentMode.textContent = chineseName || stateKey || 'Có lỗi';
      }

      // Cập nhật hành động hiện tại
      if (currentAction) {
        currentAction.textContent = systemData.action || 'Có lỗi';
      }

      // Cập nhật tầng hiện tại
      if (currentFloor) {
        currentFloor.textContent = systemData.current_floor || 'Tầng một';
      }

      // Cập nhật phòng hiện tại
      if (currentRoom) {
        const roomName = systemData.current_departments_name;
        currentRoom.textContent = roomName || 'Cổng bệnh viện';
      }
    } else {
      // Nếu phân tích cú pháp dữ liệu thất bại, hiển thị thông báo lỗi
      if (currentMode) currentMode.textContent = 'Có lỗi';
      if (currentAction) currentAction.textContent = 'Có lỗi';
      if (currentFloor) currentFloor.textContent = 'Tầng một';
      if (currentRoom) currentRoom.textContent = 'Cổng bệnh viện';
    }
  }

  // Khởi tạo hiển thị trạng thái
  updateStatusDisplay();
}

// Lấy dữ liệu trang bị từ items_list dựa trên tên trang bị
function getItemFromItemsList(itemName) {
  try {
    if (!itemName) return null;

    const itemsListElement = document.getElementById('items_list');
    if (!itemsListElement) {
      console.error('Không tìm thấy nguồn dữ liệu items_list');
      return null;
    }

    const itemsData = JSON.parse(itemsListElement.textContent);
    const items = itemsData.items_list || [];

    // Tìm trang bị theo tên
    const foundItem = items.find(item => item.name === itemName);

    if (foundItem) {
      console.log('Đã tìm thấy trang bị trong items_list:', foundItem.name, 'Ảnh:', foundItem.image);
      return foundItem;
    } else {
      console.warn('Không tìm thấy trang bị trong items_list:', itemName);
      return null;
    }
  } catch (e) {
    console.error('Lấy dữ liệu trang bị từ items_list thất bại:', e);
    return null;
  }
}

// Chức năng hiển thị thông tin người dùng
function setupUserInfoDisplay() {
  // Phân tích cú pháp dữ liệu người dùng
  function parseUserData() {
    const systemDataYaml = getSystemDataFromXml();
    if (!systemDataYaml) {
      console.error('Không tìm thấy nguồn dữ liệu system_data_xml');
      return null;
    }

    try {
      const data = jsyaml.load(systemDataYaml);
      return data.system_data?.user || null;
    } catch (e) {
      console.error('Phân tích cú pháp dữ liệu người dùng thất bại:', e);
      return null;
    }
  }

  // Hiển thị thông tin người dùng
  function displayUserInfo() {
    const userData = parseUserData();
    if (!userData) return;

    // Cập nhật thông tin cơ bản của người dùng
    const userName = document.querySelector('.info-section span:nth-child(2)');
    if (userName) {
      userName.textContent = userData.name;
    }

    // Cập nhật giá trị sinh mệnh
    const healthText = document.querySelector('.stat-bar').parentElement.querySelector('span:last-child');
    const healthBar = document.querySelector('.stat-fill.bg-hp');
    if (healthText && healthBar) {
      healthText.textContent = userData.health;
      // Tính toán phần trăm sức khỏe (9/10 = 90%)
      const [current, max] = userData.health.split('/').map(Number);
      const healthPercent = (current / max) * 100;
      healthBar.style.width = `${healthPercent}%`;
    }

    // Cập nhật giá trị thể lực
    const staminaText = document.querySelectorAll('.stat-bar')[1].parentElement.querySelector('span:last-child');
    const staminaBar = document.querySelector('.stat-fill.bg-mp');
    if (staminaText && staminaBar) {
      staminaText.textContent = userData.stamina;
      // Tính toán phần trăm thể lực
      const [current, max] = userData.stamina.split('/').map(Number);
      const staminaPercent = (current / max) * 100;
      staminaBar.style.width = `${staminaPercent}%`;
    }

    // Cập nhật thuộc tính cơ bản
    const baseAttack = document.getElementById('base-attack');
    const baseDefense = document.getElementById('base-defense');
    if (baseAttack && userData.base_attack) {
      baseAttack.textContent = userData.base_attack;
    }
    if (baseDefense && userData.base_defense) {
      baseDefense.textContent = userData.base_defense;
    }

    // Cập nhật tổng thuộc tính
    const totalAttack = document.getElementById('total-attack');
    const totalDefense = document.getElementById('total-defense');
    if (totalAttack && userData.attack) {
      totalAttack.textContent = userData.attack;
    }
    if (totalDefense && userData.defense) {
      totalDefense.textContent = userData.defense;
    }

    // Cập nhật thông tin trang bị
    const equipment = userData.equipped_equipment;
    const hasEquipment = equipment && equipment.name && equipment.name.trim() !== '';

    // Lấy phần tử hiển thị trang bị
    const equipmentImage = document.getElementById('equipment-image');
    const equipmentName = document.getElementById('equipment-name');
    const equipmentType = document.getElementById('equipment-type');
    const equipmentLevel = document.getElementById('equipment-level');
    const equipmentAttack = document.getElementById('equipment-attack');
    const equipmentDefense = document.getElementById('equipment-defense');
    const equipmentDescription = document.getElementById('equipment-description');
    const equipmentSpecial = document.getElementById('equipment-special');
    const equipmentSpecialText = document.getElementById('equipment-special-text');

    if (hasEquipment) {
      // Hiển thị khi có trang bị
      if (equipmentImage) {
        // Khớp dữ liệu trang bị từ items_list dựa trên tên trang bị
        const itemData = getItemFromItemsList(equipment.name);

        equipmentImage.src =
          itemData?.image ||
          equipment.image ||
          'data:image/svg+xml;base64,';
        equipmentImage.alt = equipment.name;
      }

      if (equipmentName) {
        equipmentName.textContent = equipment.name;
      }

      if (equipmentType) {
        equipmentType.textContent = equipment.type || 'Trang bị';
      }

      if (equipmentLevel) {
        equipmentLevel.textContent = equipment.item_lv ? `Lv.${equipment.item_lv}` : '';
      }

      if (equipmentAttack) {
        const attackBonus = equipment.attack_bonus || 0;
        equipmentAttack.textContent = `Tấn công+${attackBonus}`;
        equipmentAttack.style.display = attackBonus > 0 ? 'inline-block' : 'none';
      }

      if (equipmentDefense) {
        const defenseBonus = equipment.defense_bonus || 0;
        equipmentDefense.textContent = `Phòng ngự+${defenseBonus}`;
        equipmentDefense.style.display = defenseBonus > 0 ? 'inline-block' : 'none';
      }

      if (equipmentDescription) {
        equipmentDescription.textContent = equipment.description || 'Không có mô tả';
      }

      if (equipment.special_attribute && equipment.special_attribute.trim()) {
        if (equipmentSpecialText) {
          equipmentSpecialText.textContent = equipment.special_attribute;
        }
        if (equipmentSpecial) {
          equipmentSpecial.style.display = 'block';
        }
      } else if (equipmentSpecial) {
        equipmentSpecial.style.display = 'none';
      }
    } else {
      // Hiển thị khi không có trang bị
      if (equipmentImage) {
        equipmentImage.src =
          'data:image/svg+xml;base64,';
        equipmentImage.alt = 'Không có trang bị';
      }

      if (equipmentName) {
        equipmentName.textContent = 'Không có trang bị';
        equipmentName.style.color = '#9CA3AF';
      }

      if (equipmentType) {
        equipmentType.textContent = 'Trống';
        equipmentType.style.color = '#9CA3AF';
      }

      if (equipmentLevel) {
        equipmentLevel.textContent = '';
      }

      if (equipmentAttack) {
        equipmentAttack.style.display = 'none';
      }

      if (equipmentDefense) {
        equipmentDefense.style.display = 'none';
      }

      if (equipmentDescription) {
        equipmentDescription.textContent = 'Hiện không trang bị vật phẩm nào';
        equipmentDescription.style.color = '#9CA3AF';
        equipmentDescription.style.fontStyle = 'italic';
      }

      if (equipmentSpecial) {
        equipmentSpecial.style.display = 'none';
      }
    }
  }

  // Khởi tạo hiển thị thông tin người dùng
  displayUserInfo();
}

// Chức năng hiển thị thông tin kẻ địch
function setupEnemyInfoDisplay() {
  // Chọn ngẫu nhiên ảnh nền
  function getRandomBackgroundImage() {
    try {
      const backgroundImgElement = document.getElementById('background_img');
      if (!backgroundImgElement) {
        console.error('Không tìm thấy nguồn dữ liệu background_img');
        return null;
      }

      const backgroundImages = JSON.parse(backgroundImgElement.textContent);
      if (!backgroundImages || backgroundImages.length === 0) {
        console.error('Mảng ảnh nền trống');
        return null;
      }

      const randomIndex = Math.floor(Math.random() * backgroundImages.length);
      return backgroundImages[randomIndex];
    } catch (e) {
      console.error('Lấy ảnh nền ngẫu nhiên thất bại:', e);
      return null;
    }
  }

  // Phân tích cú pháp dữ liệu kẻ địch
  function parseEnemyData() {
    const systemDataYaml = getSystemDataFromXml();
    if (!systemDataYaml) {
      console.error('Không tìm thấy nguồn dữ liệu system_data_xml');
      return null;
    }

    try {
      const data = jsyaml.load(systemDataYaml);
      // Đường dẫn phân tích cú pháp chính xác: dữ liệu kẻ địch nằm trong data.system_data.enemy
      return data.system_data?.enemy || null;
    } catch (e) {
      console.error('Phân tích cú pháp dữ liệu kẻ địch thất bại:', e);
      return null;
    }
  }

  // Lấy URL ảnh kẻ địch
  function getEnemyImageUrl(enemyData) {
    try {
      // Lấy nguồn dữ liệu enemies_data
      const enemiesDataElement = document.getElementById('enemies_data');
      if (!enemiesDataElement) {
        console.error('Không tìm thấy nguồn dữ liệu enemies_data');
        return null;
      }

      const enemiesData = JSON.parse(enemiesDataElement.textContent);

      // Lấy type, image_id và current_state của enemy
      const enemyType = enemyData.attributes?.type;
      const imageId = enemyData.image;
      const currentState = enemyData.attributes?.current_state;
      const identity = enemyData.attributes?.identity;

      if (!enemyType || !imageId || !currentState) {
        console.error('Thiếu thông tin type, image hoặc current_state trong dữ liệu kẻ địch', {
          type: enemyType, 
          image: imageId, 
          current_state: currentState
        });
        return null;
      }

      // Xử lý đặc biệt cho Viện trưởng: thân phận Viện trưởng là duy nhất, image cố định là 1
      if (identity === "Viện trưởng") {
        const deanData = enemiesData.enemies_data.find(enemy => enemy.identity === "Viện trưởng");
        if (deanData && deanData.images) {
          const imageData = deanData.images.find(img => img.image_id === 1);
          if (imageData && imageData[currentState]) {
            return imageData[currentState];
          }
        }
        console.error(`Không tìm thấy ảnh Viện trưởng: current_state=${currentState}`);
        return null;
      }

      // Logic xử lý cho các kẻ địch khác: khớp type trong system_data với type trong enemies_data
      const matchingEnemyType = enemiesData.enemies_data.find(enemy => enemy.type === enemyType);

      if (!matchingEnemyType) {
        console.error(`Không tìm thấy loại kẻ địch phù hợp: ${enemyType}`);
        return null;
      }

      // Tìm image_id tương ứng trong loại kẻ địch đã khớp
      if (matchingEnemyType.images) {
        const imageData = matchingEnemyType.images.find(img => img.image_id === imageId);
        if (imageData && imageData[currentState]) {
          return imageData[currentState];
        }
      }

      console.error(`Không tìm thấy ảnh kẻ địch tương ứng: type=${enemyType}, image_id=${imageId}, current_state=${currentState}`);
      return null;
    } catch (e) {
      console.error('Lấy ảnh kẻ địch thất bại:', e);
      return null;
    }
  }

  // Hiển thị thông tin kẻ địch
  function displayEnemyInfo() {
    const enemyData = parseEnemyData();
    const enemySection = document.getElementById('enemy-info-section');
    const noEnemyBackground = document.getElementById('no-enemy-background');
    const enemyContent = document.getElementById('enemy-content');

    if (!enemySection || !noEnemyBackground || !enemyContent) return;

    // Trước tiên hiển thị toàn bộ khu vực thông tin kẻ địch
    enemySection.style.display = 'block';

    // Lấy trạng thái is_hava_enemy trong system_data
    let isHaveEnemy = false;
    try {
      const systemDataYaml = getSystemDataFromXml();
      if (systemDataYaml) {
        const data = jsyaml.load(systemDataYaml);
        isHaveEnemy = data.system_data?.enemy?.is_hava_enemy || false;
        console.log('Trạng thái is_hava_enemy:', isHaveEnemy, 'Dữ liệu kẻ địch:', data.system_data?.enemy);
      }
    } catch (e) {
      console.error('Phân tích cú pháp system_data thất bại:', e);
    }

    if (!isHaveEnemy) {
      // Hiển thị ảnh nền khi không có kẻ địch
      noEnemyBackground.style.display = 'block';
      enemyContent.style.display = 'none';

      // Đặt ảnh nền ngẫu nhiên
      const randomImageUrl = getRandomBackgroundImage();
      const backgroundImageElement = document.getElementById('random-background-image');
      if (backgroundImageElement && randomImageUrl) {
        backgroundImageElement.src = randomImageUrl;
      }

      return;
    }

    // Hiển thị thông tin kẻ địch khi có kẻ địch
    noEnemyBackground.style.display = 'none';
    enemyContent.style.display = 'block';

    // Khi is_hava_enemy là true, vẫn hiển thị khu vực thông tin kẻ địch ngay cả khi dữ liệu không đầy đủ
    // Chỉ hiển thị thông tin giữ chỗ khi dữ liệu hoàn toàn bị thiếu
    if (!enemyData || !enemyData.name) {
      console.warn('Dữ liệu kẻ địch không đầy đủ, nhưng is_hava_enemy là true, hiển thị thông tin kẻ địch mặc định');
      // Đặt thông tin kẻ địch mặc định thay vì hiển thị ảnh nền
      const enemyNameElement = document.getElementById('enemy-name');
      if (enemyNameElement) {
        enemyNameElement.textContent = 'Kẻ địch không xác định';
      }
      // Tiếp tục thực hiện logic hiển thị thông tin kẻ địch tiếp theo, không return
    }

    // Cập nhật ảnh kẻ địch
    const enemyImage = document.getElementById('enemy-image');
    if (enemyImage) {
      // Lấy URL ảnh từ enemies_data dựa trên system_data.enemy.image và current_state
      const imageUrl = getEnemyImageUrl(enemyData);
      if (imageUrl) {
        enemyImage.src = imageUrl;
      } else {
        // Nếu không tìm thấy ảnh tương ứng, sử dụng đường dẫn ảnh mặc định làm phương án dự phòng
      const imageName = enemyData.name.toLowerCase();
      enemyImage.src = `characters/enemy/${imageName}.png`;
      }
      enemyImage.alt = enemyData.name;
    }

    // 更新基本信息
    const enemyName = document.getElementById('enemy-name');
    if (enemyName) {
      enemyName.textContent = enemyData.name;
    }

    const enemyCurrentState = document.getElementById('enemy-current-state');
    if (enemyCurrentState && enemyData.attributes.current_state) {
      enemyCurrentState.textContent = enemyData.attributes.current_state;
    }

    const enemyCareer = document.getElementById('enemy-career');
    if (enemyCareer && enemyData.attributes.career) {
      enemyCareer.textContent = enemyData.attributes.career;
    }

    const enemyType = document.getElementById('enemy-type');
    if (enemyType && enemyData.attributes.type) {
      enemyType.textContent = enemyData.attributes.type;
    }

    const enemyIdentity = document.getElementById('enemy-identity');
    if (enemyIdentity && enemyData.attributes.identity) {
      enemyIdentity.textContent = enemyData.attributes.identity;
    }

    const enemyClimaxProgress = document.getElementById('enemy-climax-progress');
    if (
      enemyClimaxProgress &&
      enemyData.profile &&
      enemyData.profile.interaction &&
      enemyData.profile.interaction.climax_progress
    ) {
      enemyClimaxProgress.textContent = enemyData.profile.interaction.climax_progress;
    }

    // Cập nhật thuộc tính chiến đấu
    const enemyHealth = document.getElementById('enemy-health');
    const enemyHealthBar = document.getElementById('enemy-health-bar');
    if (enemyHealth && enemyHealthBar && enemyData.stats.health) {
      enemyHealth.textContent = enemyData.stats.health;
      // Tính toán phần trăm giá trị sinh mệnh
      const [current, max] = enemyData.stats.health.split('/').map(Number);
      const healthPercent = max > 0 ? (current / max) * 100 : 0;
      enemyHealthBar.style.width = `${healthPercent}%`;
    }

    const enemyAttack = document.getElementById('enemy-attack');
    if (enemyAttack && enemyData.stats.attack) {
      enemyAttack.textContent = enemyData.stats.attack;
    }

    const enemyDefense = document.getElementById('enemy-defense');
    if (enemyDefense && enemyData.stats.defense) {
      enemyDefense.textContent = enemyData.stats.defense;
    }

    // Cập nhật hồ sơ nhân vật
    const enemyDailyPersonality = document.getElementById('enemy-daily-personality');
    if (enemyDailyPersonality && enemyData.profile.daily_personality) {
      enemyDailyPersonality.textContent = enemyData.profile.daily_personality;
    }

    const enemyStature = document.getElementById('enemy-stature');
    if (enemyStature && enemyData.profile.stature) {
      enemyStature.textContent = enemyData.profile.stature;
    }

    const enemyIntro = document.getElementById('enemy-intro');
    if (enemyIntro && enemyData.profile.intro) {
      enemyIntro.textContent = enemyData.profile.intro;
    }

    // Cập nhật trích dẫn đối thoại
    const enemyTalkQuotes = document.getElementById('enemy-talk-quotes');
    if (enemyTalkQuotes && enemyData.talk) {
      // Xóa các trích dẫn hiện có
      enemyTalkQuotes.innerHTML = '';

      // Thêm trích dẫn mới
      enemyData.talk.forEach(quote => {
        const quoteBox = document.createElement('div');
        quoteBox.className = 'quote-box';
        quoteBox.textContent = `"${quote}"`;
        enemyTalkQuotes.appendChild(quoteBox);
      });
    }
  }

  // Khởi tạo hiển thị thông tin kẻ địch
  displayEnemyInfo();

  // Đảm bảo ảnh trong thông tin kẻ địch có thể được nhấp để phóng to
  const enemyImage = document.getElementById('enemy-image');
  if (enemyImage) {
    enemyImage.addEventListener('click', function(event) {
      const imgSrc = event.target.src;
      const fullscreenViewer = document.getElementById('fullscreen-image-viewer');
      const fullscreenImage = document.getElementById('fullscreen-image');

      if (fullscreenViewer && fullscreenImage && imgSrc) {
        fullscreenImage.src = imgSrc;
        fullscreenViewer.classList.add('show');

        // Ngăn chặn sự kiện nổi bọt
        event.stopPropagation();
      }
    });
  }

  // Thêm chức năng nhấp để phóng to cho ảnh nền
  const backgroundImage = document.getElementById('random-background-image');
  if (backgroundImage) {
    backgroundImage.addEventListener('click', function(event) {
      const imgSrc = event.target.src;
      const fullscreenViewer = document.getElementById('fullscreen-image-viewer');
      const fullscreenImage = document.getElementById('fullscreen-image');

      if (fullscreenViewer && fullscreenImage && imgSrc) {
        fullscreenImage.src = imgSrc;
        fullscreenViewer.classList.add('show');

        // Ngăn chặn sự kiện nổi bọt
        event.stopPropagation();
      }
    });
  }

  // Thêm chức năng cho nút bách khoa ở trạng thái nền
  const bgCompendiumButton = document.getElementById('mini-enemy-compendium-button-bg');
  if (bgCompendiumButton) {
    bgCompendiumButton.addEventListener('click', function(event) {
      // Mở bách khoa toàn thư kẻ địch
      const enemyCompendiumModal = document.getElementById('enemy-compendium-modal');
      if (enemyCompendiumModal) {
        enemyCompendiumModal.style.display = 'flex';
      }
      event.stopPropagation();
    });
  }
}

// Chức năng hiển thị quá trình chiến đấu
function setupBattleProcessDisplay() {
  // Phân tích cú pháp dữ liệu quá trình chiến đấu
  function parseBattleProcessData() {
    const systemDataYaml = getSystemDataFromXml();
    if (!systemDataYaml) {
      console.error('Không tìm thấy nguồn dữ liệu system_data_xml');
      return { hasProperty: false, data: [] };
    }

    try {
      const data = jsyaml.load(systemDataYaml);
      const systemData = data.system_data;

      // Kiểm tra xem có thuộc tính battle_process hay không (bất kể giá trị của nó là gì)
      const hasBattleProcessProperty = systemData && 'battle_process' in systemData;

      if (!hasBattleProcessProperty) {
        return { hasProperty: false, data: [] };
      }

      const battleProcess = systemData.battle_process;
      console.log('Phát hiện thuộc tính battle_process, bắt đầu hiển thị quá trình chiến đấu:', battleProcess);
      console.log('Nội dung đầy đủ của system_data:', systemData);

      // Nếu battle_process là null, undefined hoặc mảng rỗng, trả về mảng rỗng nhưng đánh dấu là có thuộc tính
      if (!battleProcess || (Array.isArray(battleProcess) && battleProcess.length === 0)) {
        return { hasProperty: true, data: [] };
      }

      // Nếu battle_process là một mảng, cần trích xuất các giá trị trong đó
      if (Array.isArray(battleProcess)) {
        // Xử lý các đối tượng trong mảng, trích xuất dữ liệu chiến đấu thực tế
        const extractedData = [];
        battleProcess.forEach(item => {
          if (typeof item === 'object' && item !== null) {
            // Nếu là đối tượng, trích xuất tất cả các giá trị (giá trị của round_1, round_2, v.v.)
            Object.values(item).forEach(value => {
              if (typeof value === 'string') {
                extractedData.push(value);
              }
            });
          } else if (typeof item === 'string') {
            // Nếu trực tiếp là chuỗi, thêm trực tiếp
            extractedData.push(item);
          }
        });
        console.log('Dữ liệu chiến đấu được trích xuất từ mảng:', extractedData);
        return { hasProperty: true, data: extractedData };
      }

      // Nếu battle_process là một đối tượng, chuyển đổi thành mảng
      if (typeof battleProcess === 'object') {
        const extractedData = Object.values(battleProcess);
        console.log('Dữ liệu chiến đấu được trích xuất từ đối tượng:', extractedData);
        return { hasProperty: true, data: extractedData };
      }

      // Các trường hợp khác, gói giá trị đơn lẻ thành một mảng
      console.warn('Định dạng dữ liệu battle_process không như mong đợi, đang gói nó thành một mảng:', battleProcess);
      return { hasProperty: true, data: [battleProcess] };
    } catch (e) {
      console.error('Phân tích cú pháp dữ liệu quá trình chiến đấu thất bại:', e);
      return { hasProperty: false, data: [] };
    }
  }

  // Phân tích cú pháp dữ liệu một hiệp đấu
  function parseRoundData(roundString) {
    if (!roundString || typeof roundString !== 'string') {
      return null;
    }

    // Kiểm tra xem có phải là hiệp chạy trốn không
    if (roundString.includes('Chạy trốn')) {
      return {
        type: 'escape',
        content: roundString,
        isEscape: true,
      };
    }

    // Kiểm tra xem có phải là hiệp đấu thường không
    const parts = roundString.split('|');
    if (parts.length < 2) {
      return {
        type: 'other',
        content: roundString,
        isEscape: false,
      };
    }

    return {
      type: 'battle',
      content: roundString,
      parts: parts,
      isEscape: false,
    };
  }

  // Hiển thị một hiệp đấu
  function renderBattleRound(roundData, index) {
    if (!roundData) return '';

    const roundNumber = index + 1;
    let roundHTML = '';

    if (roundData.isEscape) {
      // Hiển thị đặc biệt cho hiệp chạy trốn
      roundHTML = `
        <div class="bg-yellow-50 rounded-lg p-3 border border-yellow-200">
          <h4 class="font-medium text-yellow-700 text-sm mb-2 flex items-center">
            <i class="fa fa-running mr-2"></i>Hiệp ${roundNumber} - Chạy trốn
          </h4>
          <div class="text-xs text-yellow-800">
            ${roundData.content}
          </div>
        </div>
      `;
    } else if (roundData.type === 'battle' && roundData.parts) {
      // Hiển thị cho hiệp đấu thường
      roundHTML = `
        <div class="bg-white/80 rounded-lg p-3 border border-gray-200">
          <h4 class="font-medium text-primary text-sm mb-2">Hiệp ${roundNumber}</h4>
          <div class="text-xs text-gray-700 grid grid-cols-1 gap-1">
      `;

      roundData.parts.forEach(part => {
        if (!part.trim()) return;

        if (part.includes('Hiệp')) {
          roundHTML += `<div class="col-span-1 font-medium text-primary mb-1">${part}</div>`;
        } else if (part.includes('Lực tấn công') || part.includes('Lực phòng ngự')) {
          roundHTML += `<div class="text-blue-600">${part}</div>`;
        } else if (part.includes('Trừ') && part.includes('Giá trị sinh mệnh')) {
          roundHTML += `<div class="text-red-600 font-medium">${part}</div>`;
        } else if (part.includes('Giá trị sinh mệnh')) {
          roundHTML += `<div class="text-green-600">${part}</div>`;
        } else if (part.includes('Tiêu hao thể lực') || part.includes('Thể lực còn lại')) {
          roundHTML += `<div class="text-blue-500">${part}</div>`;
        } else if (part.includes('Kết quả chạy trốn')) {
          roundHTML += `<div class="text-yellow-600 font-medium">${part}</div>`;
        } else {
          roundHTML += `<div class="text-gray-600">${part}</div>`;
        }
      });

      roundHTML += `
          </div>
        </div>
      `;
    } else {
      // Hiển thị cho các loại hiệp đấu khác
      roundHTML = `
        <div class="bg-gray-50 rounded-lg p-3 border border-gray-200">
          <h4 class="font-medium text-gray-700 text-sm mb-2">Hiệp ${roundNumber}</h4>
          <div class="text-xs text-gray-600">
            ${roundData.content}
          </div>
        </div>
      `;
    }

    return roundHTML;
  }

  // Hiển thị quá trình chiến đấu
  function displayBattleProcess() {
    const result = parseBattleProcessData();
    const battleContent = document.getElementById('battle-text-content');

    if (!battleContent) {
      console.warn('Không tìm thấy khu vực hiển thị nội dung chiến đấu');
      return;
    }

    // Nếu không có thuộc tính battle_process trong nguồn dữ liệu, hiển thị nội dung mặc định
    if (!result.hasProperty) {
      battleContent.innerHTML = `
        <div class="text-center text-gray-500 py-8">
          <i class="fa fa-shield text-4xl mb-4 text-enemy/50"></i>
          <p>Hiện không có trận chiến nào đang diễn ra</p>
          <p class="text-sm mt-2">Khi trận chiến bắt đầu, nơi đây sẽ hiển thị quá trình chiến đấu chi tiết</p>
        </div>
      `;
      return;
    }

    // Nếu có thuộc tính battle_process, bất kể dữ liệu có trống hay không, đều phải hiển thị khu vực quá trình chiến đấu
    const battleData = result.data;
    let battleHTML = '<div class="space-y-3">';

    if (battleData.length === 0) {
      // Trường hợp có thuộc tính battle_process nhưng dữ liệu trống
      battleHTML += `
        <div class="bg-gradient-to-r from-primary/10 to-secondary/10 rounded-lg p-3 border border-primary/20">
          <h3 class="font-bold text-primary text-base flex items-center">
            <i class="fa fa-swords mr-2"></i>Nhật ký chiến đấu (Không có dữ liệu chiến đấu)
          </h3>
        </div>
        <div class="text-center text-gray-600 py-6">
          <i class="fa fa-info-circle text-2xl mb-2 text-gray-400"></i>
          <p>Chưa có dữ liệu chiến đấu</p>
          <p class="text-sm mt-1"></p>
        </div>
      `;
    } else {
      // Trường hợp có thuộc tính battle_process và có dữ liệu
      battleHTML += `
        <div class="bg-gradient-to-r from-primary/10 to-secondary/10 rounded-lg p-3 border border-primary/20">
          <h3 class="font-bold text-primary text-base flex items-center">
            <i class="fa fa-swords mr-2"></i>Nhật ký chiến đấu (Tổng cộng ${battleData.length} hiệp)
          </h3>
        </div>
      `;

      // Hiển thị mỗi hiệp
      battleData.forEach((round, index) => {
        const roundData = parseRoundData(round);
        const roundHTML = renderBattleRound(roundData, index);
        if (roundHTML) {
          battleHTML += roundHTML;
        }
      });

      console.log(`Hiển thị quá trình chiến đấu hoàn tất, tổng cộng hiển thị ${battleData.length} hiệp`);
    }

    battleHTML += '</div>';
    battleContent.innerHTML = battleHTML;
  }

  // Khởi tạo hiển thị quá trình chiến đấu
  displayBattleProcess();
}

// Chức năng bách khoa toàn thư kẻ địch
function setupEnemyCompendium() {
  // Lấy các phần tử DOM
  const modal = document.getElementById('enemy-compendium-modal');
  const openButton = document.getElementById('mini-enemy-compendium-button');
  const closeButton = document.getElementById('close-modal');
  const prevButton = document.getElementById('prev-enemy');
  const nextButton = document.getElementById('next-enemy');

  // Dữ liệu kẻ địch và chỉ mục được chọn hiện tại
  let enemies = [];
  let currentEnemyIndex = 0;
  let currentImageId = 1; // ID ảnh được chọn hiện tại

  // Phân tích cú pháp dữ liệu kẻ địch
  function parseEnemyData() {
    try {
      // Đọc từ nguồn dữ liệu JSON enemies_data
      const enemiesDataElement = document.getElementById('enemies_data');
      if (!enemiesDataElement) {
        console.error('Không tìm thấy nguồn dữ liệu enemies_data');
      return false;
    }

      const enemiesData = JSON.parse(enemiesDataElement.textContent);
      enemies = enemiesData.enemies_data || [];
      return true;
    } catch (e) {
      console.error('Phân tích cú pháp dữ liệu kẻ địch thất bại:', e);
      return false;
    }
  }

  // Cập nhật hiển thị ảnh kẻ địch - hiển thị 3 trạng thái của cùng một image_id
  function updateEnemyImages(enemy, imageId) {
    const defaultImage = 'data:image/svg+xml;base64,';

    if (!enemy.images || !Array.isArray(enemy.images)) {
      console.warn('Không có mảng images trong dữ liệu kẻ địch');
      // Đặt ảnh mặc định
      const imageIds = ['mutation', 'normal-talk', 'normal-sex'];
      imageIds.forEach(id => {
        const img = document.getElementById(`compendium-enemy-image-${id}`);
        if (img) {
          img.src = defaultImage;
          img.alt = `Ảnh ${enemy.identity || 'Kẻ địch'}`;
        }
      });
      return;
    }

    // Tìm dữ liệu ảnh tương ứng với image_id
    const imageData = enemy.images.find(imgObj => imgObj.image_id === imageId);

    if (!imageData) {
      console.warn(`Không tìm thấy dữ liệu ảnh có image_id là ${imageId}`);
      // Đặt ảnh mặc định
      const imageIds = ['mutation', 'normal-talk', 'normal-sex'];
      imageIds.forEach(id => {
        const img = document.getElementById(`compendium-enemy-image-${id}`);
        if (img) {
          img.src = defaultImage;
          img.alt = `Ảnh ${enemy.identity || 'Kẻ địch'}`;
        }
      });
      return;
    }

    // Hiển thị 3 trạng thái của cùng một image_id
    const states = [
      { id: 'mutation', state: 'Biến dị' },
      { id: 'normal-talk', state: 'Bình thường-Đối thoại' },
      { id: 'normal-sex', state: 'Bình thường-Tình dục' }
    ];

    states.forEach(stateInfo => {
      const img = document.getElementById(`compendium-enemy-image-${stateInfo.id}`);
      if (img) {
        if (imageData[stateInfo.state]) {
          img.src = imageData[stateInfo.state];
          img.alt = `${enemy.identity || 'Kẻ địch'} ${stateInfo.state}`;

          // Thêm chức năng nhấp để phóng to
          img.onclick = () => {
            if (imageData[stateInfo.state]) {
              showFullscreenImage({ target: { src: imageData[stateInfo.state] } });
            }
          };
        } else {
          img.src = defaultImage;
          img.alt = `${enemy.identity || 'Kẻ địch'} ${stateInfo.state}`;
        }
      }
    });
  }

  // Cập nhật thông tin điều hướng ảnh
  function updateImageNavigation(enemy) {
    const currentImageIdElement = document.getElementById('current-image-id');
    const totalImagesElement = document.getElementById('total-images');
    const prevBtn = document.getElementById('prev-image-btn');
    const nextBtn = document.getElementById('next-image-btn');

    if (currentImageIdElement) {
      currentImageIdElement.textContent = currentImageId;
    }

    if (totalImagesElement && enemy.images) {
      totalImagesElement.textContent = enemy.images.length;
    }

    // Cập nhật trạng thái nút
    if (prevBtn) {
      prevBtn.disabled = currentImageId <= 1;
    }

    if (nextBtn && enemy.images) {
      nextBtn.disabled = currentImageId >= enemy.images.length;
    }
  }

  // Khởi tạo sự kiện cho nút điều hướng ảnh
  function initImageNavigationButtons() {
    const prevBtn = document.getElementById('prev-image-btn');
    const nextBtn = document.getElementById('next-image-btn');

    if (prevBtn) {
      prevBtn.onclick = (e) => {
        e.preventDefault();
        if (currentImageId > 1) {
          currentImageId--;
          if (enemies.length > 0 && enemies[currentEnemyIndex]) {
            updateEnemyImages(enemies[currentEnemyIndex], currentImageId);
            updateImageNavigation(enemies[currentEnemyIndex]);
          }
        }
      };
    }

    if (nextBtn) {
      nextBtn.onclick = (e) => {
        e.preventDefault();
        const enemy = enemies[currentEnemyIndex];
        if (enemy && enemy.images && currentImageId < enemy.images.length) {
          currentImageId++;
          updateEnemyImages(enemy, currentImageId);
          updateImageNavigation(enemy);
        }
      };
    }
  }

  // Cập nhật hiển thị chi tiết kẻ địch
  function updateEnemyDetail() {
    if (enemies.length === 0 || !enemies[currentEnemyIndex]) return;

    const enemy = enemies[currentEnemyIndex];

    // Cập nhật ảnh kẻ địch
    // Đặt lại ID ảnh hiện tại về 1
    currentImageId = 1;
    updateEnemyImages(enemy, currentImageId);
    updateImageNavigation(enemy);
    initImageNavigationButtons();
    initImageClickEvents();

    // Logic ảnh đơn cũ đã được thay thế
    const enemyImage = document.getElementById('compendium-enemy-image-old');
    if (enemyImage) {
      // Ảnh mặc định (giữ chỗ định dạng SVG)
      const defaultImage =
        'data:image/svg+xml;base64,';

      enemyImage.alt = enemy.identity || 'Ảnh kẻ địch';

      // Nếu có trường photo và không trống, thử tải ảnh
      if (enemy.photo && enemy.photo.trim() !== '') {
        // Tạo một đối tượng Image mới để kiểm tra xem ảnh có thể tải được không
        const testImage = new Image();
        testImage.onload = function () {
          enemyImage.src = enemy.photo;
        };
        testImage.onerror = function () {
          console.warn(`Tải ảnh kẻ địch thất bại: ${enemy.photo}, sử dụng ảnh mặc định`);
          enemyImage.src = defaultImage;
        };
        testImage.src = enemy.photo;
      } else {
        // Không có trường photo hoặc trống, sử dụng ảnh mặc định
        enemyImage.src = defaultImage;
      }
    }

    // Cập nhật thông tin cơ bản
    const enemyIdentity = document.getElementById('compendium-enemy-identity');
    if (enemyIdentity) {
      enemyIdentity.textContent = enemy.identity;
    }

    const enemyType = document.getElementById('compendium-enemy-type');
    if (enemyType) {
      enemyType.textContent = enemy.type;
    }

    const appearanceFloors = document.getElementById('compendium-appearance-floors');
    if (appearanceFloors) {
      appearanceFloors.textContent = enemy.appearance_floors;
    }

    // Cập nhật thuộc tính chiến đấu
    const enemyHealth = document.getElementById('compendium-enemy-health');
    if (enemyHealth) {
      if (enemy.min_health === enemy.max_health) {
        enemyHealth.textContent = enemy.min_health;
      } else {
        enemyHealth.textContent = `${enemy.min_health}-${enemy.max_health}`;
      }
    }

    const enemyAttack = document.getElementById('compendium-enemy-attack');
    if (enemyAttack) {
      if (enemy.min_attack === enemy.max_attack) {
        enemyAttack.textContent = enemy.min_attack;
      } else {
        enemyAttack.textContent = `${enemy.min_attack}-${enemy.max_attack}`;
      }
    }

    const enemyDefense = document.getElementById('compendium-enemy-defense');
    if (enemyDefense) {
      if (enemy.min_defense === enemy.max_defense) {
        enemyDefense.textContent = enemy.min_defense;
      } else {
        enemyDefense.textContent = `${enemy.min_defense}-${enemy.max_defense}`;
      }
    }

    // Cập nhật vật phẩm rơi ra
    const dropProbabilities = document.getElementById('compendium-drop-probabilities');
    if (dropProbabilities && enemy.drop_probabilities) {
      dropProbabilities.innerHTML = '';
      enemy.drop_probabilities.forEach(drop => {
        const dropItem = document.createElement('div');
        dropItem.className =
          'flex justify-between items-center bg-white/60 px-3 py-2 rounded-lg border border-gray-200';
        dropItem.innerHTML = `
                    <span class="text-gray-700">${drop.result}</span>
                    <span class="font-medium text-item">${drop.probability}</span>
                `;
        dropProbabilities.appendChild(dropItem);
      });
    }

    // Cập nhật giới thiệu
    const enemyIntro = document.getElementById('compendium-enemy-intro');
    if (enemyIntro) {
      enemyIntro.textContent = enemy.intro;
    }

    // Cập nhật hiển thị chỉ mục
    const currentIndex = document.getElementById('current-enemy-index');
    const totalEnemies = document.getElementById('total-enemies');
    if (currentIndex) {
      currentIndex.textContent = currentEnemyIndex + 1;
    }
    if (totalEnemies) {
      totalEnemies.textContent = enemies.length;
    }

    // Cập nhật trạng thái nút điều hướng
    updateNavigationButtons();
  }

  // Cập nhật trạng thái nút điều hướng
  function updateNavigationButtons() {
    const isFirst = currentEnemyIndex === 0;
    const isLast = currentEnemyIndex === enemies.length - 1;

    prevButton.disabled = isFirst;
    nextButton.disabled = isLast;

    if (isFirst) {
      prevButton.classList.add('opacity-50', 'cursor-not-allowed');
    } else {
      prevButton.classList.remove('opacity-50', 'cursor-not-allowed');
    }

    if (isLast) {
      nextButton.classList.add('opacity-50', 'cursor-not-allowed');
    } else {
      nextButton.classList.remove('opacity-50', 'cursor-not-allowed');
    }
  }

  // Chuyển sang kẻ địch trước đó
  function showPrevEnemy() {
    if (currentEnemyIndex > 0) {
      currentEnemyIndex--;
      updateEnemyDetail();
    }
  }

  // Chuyển sang kẻ địch tiếp theo
  function showNextEnemy() {
    if (currentEnemyIndex < enemies.length - 1) {
      currentEnemyIndex++;
      updateEnemyDetail();
    }
  }

  // Mở cửa sổ bật lên
  function openModal() {
    if (!modal) {
      console.error('Không tìm thấy phần tử Modal!');
      alert('Không tìm thấy phần tử cửa sổ bật lên, vui lòng kiểm tra cấu trúc HTML');
      return;
    }

    modal.classList.remove('hidden');

    // Buộc hiển thị cửa sổ bật lên (làm phương án dự phòng)
    modal.style.display = 'flex';

    // Nếu là lần đầu mở, khởi tạo dữ liệu
    if (enemies.length === 0) {
      if (parseEnemyData()) {
        currentEnemyIndex = 0;
        updateEnemyDetail();
      } else {
        console.error('Phân tích cú pháp dữ liệu thất bại');
        alert('Tải dữ liệu kẻ địch thất bại, vui lòng kiểm tra thông báo lỗi trong console');
      }
    } else {
      // Nếu dữ liệu đã được tải, cập nhật hiển thị trực tiếp
      updateEnemyDetail();
    }
  }

  // Đóng cửa sổ bật lên
  function closeModal() {
    if (modal) {
      modal.classList.add('hidden');
      modal.style.display = 'none';
    }
  }

  // Gán sự kiện
  if (openButton) {
    openButton.addEventListener('click', openModal);
  } else {
    console.error('Không tìm thấy nút bách khoa toàn thư kẻ địch (enemy-compendium-button)');
  }

  if (closeButton) {
    closeButton.addEventListener('click', closeModal);
  } else {
    console.error('Không tìm thấy nút đóng (close-modal)');
  }

  if (prevButton) {
    prevButton.addEventListener('click', showPrevEnemy);
  } else {
    console.error('Không tìm thấy nút trước (prev-enemy)');
  }

  if (nextButton) {
    nextButton.addEventListener('click', showNextEnemy);
  } else {
    console.error('Không tìm thấy nút sau (next-enemy)');
  }

  // Nhấp bên ngoài cửa sổ bật lên để đóng
  modal.addEventListener('click', e => {
    if (e.target === modal) {
      closeModal();
    }
  });

  // Xử lý sự kiện bàn phím
  document.addEventListener('keydown', e => {
    if (modal.classList.contains('hidden')) return;

    switch (e.key) {
      case 'Escape':
        closeModal();
        break;
      case 'ArrowLeft':
        e.preventDefault();
        showPrevEnemy();
        break;
      case 'ArrowRight':
        e.preventDefault();
        showNextEnemy();
        break;
    }
  });

  // Khởi tạo sự kiện nhấp chuột vào ảnh
  function initImageClickEvents() {
    const images = [
      // Ảnh trong bách khoa toàn thư kẻ địch
      document.getElementById('compendium-enemy-image-mutation'),
      document.getElementById('compendium-enemy-image-normal-talk'),
      document.getElementById('compendium-enemy-image-normal-sex'),
      // Ảnh trong thông tin kẻ địch
      document.getElementById('enemy-image')
    ];

    images.forEach(img => {
      if (img) {
        // Xóa trình lắng nghe sự kiện trước đó (tránh gán lặp)
        img.removeEventListener('click', showFullscreenImage);
        // Thêm trình lắng nghe sự kiện nhấp chuột
        img.addEventListener('click', showFullscreenImage);
      }
    });
  }

  // Hiển thị ảnh toàn màn hình
  function showFullscreenImage(event) {
    const imgSrc = event.target.src;
    const fullscreenViewer = document.getElementById('fullscreen-image-viewer');
    const fullscreenImage = document.getElementById('fullscreen-image');

    if (fullscreenViewer && fullscreenImage && imgSrc) {
      fullscreenImage.src = imgSrc;
      fullscreenViewer.classList.add('show');

      // Ngăn chặn sự kiện nổi bọt
      event.stopPropagation();
    }
  }

  // Khởi tạo trình xem ảnh toàn màn hình
  function initFullscreenImageViewer() {
    const fullscreenViewer = document.getElementById('fullscreen-image-viewer');

    if (fullscreenViewer) {
      // Nhấp vào bất kỳ vị trí nào trên trình xem để đóng
      fullscreenViewer.addEventListener('click', function() {
        fullscreenViewer.classList.remove('show');
      });

      // Đóng bằng phím ESC
      document.addEventListener('keydown', function(e) {
        if (e.key === 'Escape' && fullscreenViewer.classList.contains('show')) {
          fullscreenViewer.classList.remove('show');
          e.stopPropagation();
        }
      });
    }
  }

  // Khởi tạo trình xem ảnh toàn màn hình
  initFullscreenImageViewer();
}

// Chức năng bách khoa toàn thư vật phẩm
function setupItemCompendium() {
  // Lấy các phần tử DOM
  const modal = document.getElementById('item-compendium-modal');
  const openButton = document.getElementById('mini-item-compendium-button');
  const closeButton = document.getElementById('close-item-modal');
  const prevButton = document.getElementById('prev-item');
  const nextButton = document.getElementById('next-item');
  const itemsGrid = document.getElementById('items-grid');

  // Dữ liệu vật phẩm và cài đặt phân trang
  let items = [];
  let currentPage = 0;
  const itemsPerPage = 4;

  // Phân tích cú pháp dữ liệu vật phẩm
  function parseItemData() {
    console.log('Bắt đầu phân tích cú pháp dữ liệu vật phẩm...');
    const jsonElement = document.getElementById('items_list');
    if (!jsonElement) {
      console.error('Không tìm thấy dữ liệu JSON có ID là items_list');
      return false;
    }

    try {
      const rawData = jsonElement.textContent;
      console.log('Dữ liệu JSON gốc:', rawData.substring(0, 200) + '...');
      const data = JSON.parse(rawData);
      items = data.items_list || [];
      console.log('Phân tích cú pháp dữ liệu vật phẩm thành công, tổng cộng', items.length, 'vật phẩm:', items);
      return true;
    } catch (e) {
      console.error('Phân tích cú pháp dữ liệu vật phẩm thất bại:', e);
      console.error('Dữ liệu gốc:', jsonElement.textContent);
      return false;
    }
  }

  // Tạo HTML thẻ vật phẩm
  function createItemCard(item, index) {
    // Ảnh mặc định
    const defaultImage =
      'data:image/svg+xml;base64,';

    // Xử lý ảnh
    const imageUrl = item.image && item.image.trim() !== '' ? item.image : defaultImage;

    // Thẻ thuộc tính
    let attributesBadges = '';
    if (item.attack_bonus && item.attack_bonus > 0) {
      attributesBadges += `<span class="bg-red-100 text-red-600 px-2 py-1 rounded text-xs font-medium">Tấn công+${item.attack_bonus}</span>`;
    }
    if (item.defense_bonus && item.defense_bonus > 0) {
      attributesBadges += `<span class="bg-blue-100 text-blue-600 px-2 py-1 rounded text-xs font-medium">Phòng ngự+${item.defense_bonus}</span>`;
    }

    return `
            <div class="bg-gradient-to-b from-white to-item/5 rounded-lg border border-item/20 overflow-hidden shadow-sm hover:shadow-md transition-all duration-300">
                <div class="w-full h-32 sm:h-36 bg-gradient-to-b from-item/5 to-primary/5 flex items-center justify-center p-2">
                    <img src="${imageUrl}" alt="${
      item.name
    }" class="w-24 h-24 sm:w-28 sm:h-28 object-contain" onerror="this.src='${defaultImage}'">
                </div>

                <div class="p-3 space-y-2">
                    <div class="text-center">
                        <h4 class="font-bold text-item text-sm sm:text-base truncate" title="${item.name}">${
      item.name
    }</h4>
                        <div class="flex items-center justify-center gap-1 mt-1">
                            <span class="bg-item/10 text-item px-2 py-0.5 rounded-full text-xs">${item.type}</span>
                            <span class="bg-gray-100 text-gray-600 px-2 py-0.5 rounded-full text-xs">Lv.${
                              item.item_lv
                            }</span>
                        </div>
                    </div>

                    ${
                      attributesBadges
                        ? `<div class="flex flex-wrap gap-1 justify-center">${attributesBadges}</div>`
                        : ''
                    }

                    <div class="text-xs text-gray-600 text-center leading-relaxed" style="min-height: 2.5rem; display: -webkit-box; -webkit-line-clamp: 2; -webkit-box-orient: vertical; overflow: hidden;" title="${
                      item.description
                    }">
                        ${item.description}
                    </div>
                </div>
            </div>
        `;
  }

  // Cập nhật hiển thị lưới vật phẩm
  function updateItemsGrid() {
    if (items.length === 0) return;

    const startIndex = currentPage * itemsPerPage;
    const endIndex = Math.min(startIndex + itemsPerPage, items.length);
    const currentPageItems = items.slice(startIndex, endIndex);

    // Tạo thẻ vật phẩm cho trang hiện tại
    let gridHTML = '<div class="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-3 sm:gap-4">';
    currentPageItems.forEach((item, index) => {
      gridHTML += createItemCard(item, startIndex + index);
    });
    gridHTML += '</div>';

    // Cập nhật nội dung lưới
    if (itemsGrid) {
      itemsGrid.innerHTML = gridHTML;
    }

    // Cập nhật thông tin phân trang
    updatePaginationInfo();

    // Cập nhật trạng thái nút điều hướng
    updateNavigationButtons();
  }

  // Cập nhật thông tin phân trang
  function updatePaginationInfo() {
    const totalPages = Math.ceil(items.length / itemsPerPage);

    const currentPageElement = document.getElementById('current-page');
    const totalPagesElement = document.getElementById('total-pages');
    const totalItemsElement = document.getElementById('total-items');

    if (currentPageElement) {
      currentPageElement.textContent = currentPage + 1;
    }
    if (totalPagesElement) {
      totalPagesElement.textContent = totalPages;
    }
    if (totalItemsElement) {
      totalItemsElement.textContent = items.length;
    }
  }

  // 更新导航按钮状态
  function updateNavigationButtons() {
    const totalPages = Math.ceil(items.length / itemsPerPage);
    const isFirstPage = currentPage === 0;
    const isLastPage = currentPage === totalPages - 1;

    prevButton.disabled = isFirstPage;
    nextButton.disabled = isLastPage;

    if (isFirstPage) {
      prevButton.classList.add('opacity-50', 'cursor-not-allowed');
    } else {
      prevButton.classList.remove('opacity-50', 'cursor-not-allowed');
    }

    if (isLastPage) {
      nextButton.classList.add('opacity-50', 'cursor-not-allowed');
    } else {
      nextButton.classList.remove('opacity-50', 'cursor-not-allowed');
    }
  }

  // Chuyển sang trang trước
  function showPrevPage() {
    if (currentPage > 0) {
      currentPage--;
      updateItemsGrid();
    }
  }

  // Chuyển sang trang sau
  function showNextPage() {
    const totalPages = Math.ceil(items.length / itemsPerPage);
    if (currentPage < totalPages - 1) {
      currentPage++;
      updateItemsGrid();
    }
  }

  // Mở cửa sổ bật lên
  function openModal() {
    if (!modal) {
      console.error('Không tìm thấy phần tử Modal!');
      alert('Không tìm thấy phần tử cửa sổ bật lên, vui lòng kiểm tra cấu trúc HTML');
      return;
    }

    // Hiển thị cửa sổ bật lên
    modal.classList.add('show');
    modal.style.display = 'flex';

    // Nếu là lần đầu mở, khởi tạo dữ liệu
    if (items.length === 0) {
      if (parseItemData()) {
        currentPage = 0;
        updateItemsGrid();
      } else {
        console.error('Phân tích cú pháp dữ liệu thất bại');
        alert('Tải dữ liệu vật phẩm thất bại, vui lòng kiểm tra thông báo lỗi trong console');
      }
    } else {
      // Nếu dữ liệu đã được tải, cập nhật hiển thị trực tiếp
      updateItemsGrid();
    }
  }

  // Đóng cửa sổ bật lên
  function closeModal() {
    if (modal) {
      modal.classList.remove('show');
      modal.style.display = 'none';
    }
  }

  // Tạo hàm khởi tạo dữ liệu toàn cục để các hàm khác gọi
  window.setupItemCompendiumData = function () {
    // Nếu là lần đầu mở, khởi tạo dữ liệu
    if (items.length === 0) {
      if (parseItemData()) {
        currentPage = 0;
        updateItemsGrid();
      } else {
        console.error('Phân tích cú pháp dữ liệu thất bại');
        alert('Tải dữ liệu vật phẩm thất bại, vui lòng kiểm tra thông báo lỗi trong console');
      }
    } else {
      // Nếu dữ liệu đã được tải, cập nhật hiển thị trực tiếp
      updateItemsGrid();
    }
  };

  // Gán sự kiện cho nút bách khoa toàn thư vật phẩm nhỏ
  if (openButton) {
    openButton.addEventListener('click', function () {
      console.log('Nút bách khoa toàn thư vật phẩm nhỏ đã được nhấp');
      openModal();
    });
    console.log('Gán sự kiện cho nút bách khoa toàn thư vật phẩm nhỏ thành công');
  } else {
    console.error('Không tìm thấy nút bách khoa toàn thư vật phẩm nhỏ (mini-item-compendium-button)');
  }

  if (closeButton) {
    closeButton.addEventListener('click', closeModal);
  } else {
    console.error('Không tìm thấy nút đóng (close-item-modal)');
  }

  if (prevButton) {
    prevButton.addEventListener('click', showPrevPage);
  } else {
    console.error('Không tìm thấy nút trang trước (prev-item)');
  }

  if (nextButton) {
    nextButton.addEventListener('click', showNextPage);
  } else {
    console.error('Không tìm thấy nút trang sau (next-item)');
  }

  // Nhấp bên ngoài cửa sổ bật lên để đóng
  modal.addEventListener('click', e => {
    if (e.target === modal) {
      closeModal();
    }
  });

  // Xử lý sự kiện bàn phím
  document.addEventListener('keydown', e => {
    if (!modal.classList.contains('show')) return;

    switch (e.key) {
      case 'Escape':
        closeModal();
        break;
      case 'ArrowLeft':
        e.preventDefault();
        showPrevPage();
        break;
      case 'ArrowRight':
        e.preventDefault();
        showNextPage();
        break;
    }
  });
}

// Chức năng trang bị vật phẩm rơi ra
function equipDroppedItem(index) {
  try {
    // Lấy dữ liệu trang bị rơi ra
    const systemDataYaml = getSystemDataFromXml();
    if (!systemDataYaml) {
      console.error('Không thể lấy dữ liệu trang bị');
      return;
    }

    const data = jsyaml.load(systemDataYaml);
    const droppedEquipments = data.system_data?.dropped_equipments;

    if (!droppedEquipments || !droppedEquipments[index]) {
      console.error('Chỉ mục trang bị không hợp lệ:', index);
      return;
    }

    const equipment = droppedEquipments[index];
    console.log('Trang bị vật phẩm:', equipment);

    // Cập nhật trang bị trên trang thông tin cá nhân
    updatePlayerEquipmentInfo(equipment);

    // Hiển thị thông báo trang bị thành công
    showEquipmentSuccessMessage(equipment.name);

    // Đánh dấu vật phẩm đã được trang bị
    markItemAsEquipped(index);
  } catch (e) {
    console.error('Trang bị vật phẩm thất bại:', e);
  }
}

// Cập nhật hiển thị trang bị trên trang thông tin cá nhân
function updatePlayerEquipmentInfo(equipment) {
  // Lấy phần tử hiển thị trang bị
  const equipmentImage = document.getElementById('equipment-image');
  const equipmentName = document.getElementById('equipment-name');
  const equipmentType = document.getElementById('equipment-type');
  const equipmentLevel = document.getElementById('equipment-level');
  const equipmentAttack = document.getElementById('equipment-attack');
  const equipmentDefense = document.getElementById('equipment-defense');
  const equipmentDescription = document.getElementById('equipment-description');
  const equipmentSpecial = document.getElementById('equipment-special');

  // Cập nhật hiển thị
  if (equipmentImage) {
    // Khớp dữ liệu trang bị từ items_list dựa trên tên trang bị
    const itemData = getItemFromItemsList(equipment.name);

    equipmentImage.src =
      itemData?.image ||
      equipment.image ||
      'data:image/svg+xml;base64,';
    equipmentImage.alt = equipment.name;
  }

  if (equipmentName) {
    equipmentName.textContent = equipment.name;
    equipmentName.style.color = ''; // Đặt lại màu sắc
  }

  if (equipmentType) {
    equipmentType.textContent = equipment.type || 'Trang bị';
    equipmentType.style.color = ''; // Đặt lại màu sắc
  }

  if (equipmentLevel) {
    equipmentLevel.textContent = equipment.item_lv ? `Lv.${equipment.item_lv}` : '';
  }

  if (equipmentAttack) {
    const attackBonus = equipment.attack_bonus || 0;
    equipmentAttack.textContent = `Tấn công+${attackBonus}`;
    equipmentAttack.style.display = attackBonus > 0 ? 'inline-block' : 'none';
  }

  if (equipmentDefense) {
    const defenseBonus = equipment.defense_bonus || 0;
    equipmentDefense.textContent = `Phòng ngự+${defenseBonus}`;
    equipmentDefense.style.display = defenseBonus > 0 ? 'inline-block' : 'none';
  }

  if (equipmentDescription) {
    equipmentDescription.textContent = equipment.description || 'Không có mô tả';
    equipmentDescription.style.color = ''; // Đặt lại màu sắc
    equipmentDescription.style.fontStyle = ''; // Đặt lại kiểu chữ
  }

  if (equipmentSpecial) {
    equipmentSpecial.style.display = 'none'; // Trang bị rơi ra tạm thời không hỗ trợ thuộc tính đặc biệt
  }

  // Cập nhật tổng thuộc tính
  updateTotalStats(equipment);
}

// Cập nhật hiển thị tổng thuộc tính
function updateTotalStats(equipment) {
  // Lấy thuộc tính cơ bản
  try {
    const systemDataYaml = getSystemDataFromXml();
    if (!systemDataYaml) return;

    const data = jsyaml.load(systemDataYaml);
    const user = data.system_data?.user;
    if (!user) return;

    const baseAttack = user.base_attack || 15;
    const baseDefense = user.base_defense || 15;
    const equipmentAttackBonus = equipment.attack_bonus || 0;
    const equipmentDefenseBonus = equipment.defense_bonus || 0;

    const totalAttack = baseAttack + equipmentAttackBonus;
    const totalDefense = baseDefense + equipmentDefenseBonus;

    // Cập nhật hiển thị
    const totalAttackElement = document.getElementById('total-attack');
    const totalDefenseElement = document.getElementById('total-defense');

    if (totalAttackElement) {
      totalAttackElement.textContent = totalAttack;
    }
    if (totalDefenseElement) {
      totalDefenseElement.textContent = totalDefense;
    }

    console.log('Cập nhật tổng thuộc tính:', { totalAttack, totalDefense });
  } catch (e) {
    console.error('Cập nhật tổng thuộc tính thất bại:', e);
  }
}

// Đánh dấu vật phẩm đã được trang bị
function markItemAsEquipped(index) {
  const droppedContainer = document.getElementById('dropped-equipment-container');
  if (droppedContainer) {
    const items = droppedContainer.querySelectorAll('.dropped-equipment-item');
    if (items[index]) {
      const button = items[index].querySelector('.equip-btn');
      if (button) {
        button.textContent = 'Đã trang bị';
        button.disabled = true;
        button.classList.remove('bg-primary', 'hover:bg-primary/80');
        button.classList.add('bg-gray-400', 'cursor-not-allowed');
      }
    }
  }
}

// Chức năng trang bị vật phẩm (phiên bản cũ, duy trì tính tương thích)
function equipItem(index, itemName, itemType, itemDescription) {
  console.log('Trang bị vật phẩm (phiên bản cũ):', { index, itemName, itemType, itemDescription });

  // Cập nhật chi tiết trang bị trên giao diện chính
  updatePlayerEquipment(itemType, {
    name: itemName,
    type: itemType,
    description: itemDescription,
  });

  // Hiển thị thông báo trang bị thành công
  showEquipmentSuccessMessage(itemName);

  // Xóa vật phẩm đã trang bị (tùy chọn: xóa khỏi danh sách rơi)
  removeEquippedItemFromDrops(index);
}

// Cập nhật trang bị của người chơi
function updatePlayerEquipment(slotType, equipment) {
  // Xác định ô trang bị dựa trên loại trang bị
  let slotId = '';
  switch (slotType) {
    case 'weapon':
      slotId = 'slot-weapon';
      break;
    case 'armor':
      slotId = 'slot-armor';
      break;
    case 'accessory':
      slotId = 'slot-accessory';
      break;
    default:
      slotId = 'slot-weapon'; // Ô vũ khí mặc định
  }

  const slot = document.getElementById(slotId);
  if (slot) {
    // Cập nhật hiển thị ô trang bị
    slot.innerHTML = `
            <div class="w-full h-full bg-gradient-to-br from-blue-100 to-blue-200 border-2 border-blue-300 rounded-lg flex items-center justify-center cursor-pointer hover:from-blue-200 hover:to-blue-300 transition-all duration-300">
                <div class="text-center">
                    <i class="fa ${gameState.getEquipmentIcon(slotType)} text-blue-600 text-xl mb-1"></i>
                    <div class="text-xs font-medium text-blue-700">${equipment.name}</div>
                </div>
            </div>
        `;

    // Thêm chú giải công cụ
    slot.title = `${equipment.name}\n${equipment.description}`;
  }
}

// Hiển thị thông báo trang bị thành công
function showEquipmentSuccessMessage(itemName) {
  // Tạo tin nhắn thông báo tạm thời
  const message = document.createElement('div');
  message.className = 'fixed top-4 right-4 bg-green-500 text-white px-4 py-2 rounded-lg shadow-lg z-50';
  message.textContent = `Trang bị thành công: ${itemName}`;

  document.body.appendChild(message);

  // Tự động xóa sau 3 giây
  setTimeout(() => {
    if (message.parentNode) {
      message.parentNode.removeChild(message);
    }
  }, 3000);
}

// Xóa vật phẩm đã trang bị khỏi danh sách rơi
function removeEquippedItemFromDrops(index) {
  const droppedContainer = document.getElementById('dropped-equipment-container');
  if (droppedContainer) {
    const items = droppedContainer.querySelectorAll('.dropped-equipment-item');
    if (items[index]) {
      items[index].style.opacity = '0.5';
      items[index].style.pointerEvents = 'none';

      // Cập nhật văn bản nút
      const button = items[index].querySelector('.equip-btn');
      if (button) {
        button.textContent = 'Đã trang bị';
        button.disabled = true;
      }
    }
  }
}

// Chức năng cửa sổ bật lên khi thua game
function setupGameFailureModal() {
  const modal = document.getElementById('game-failure-modal');
  const closeButton = document.getElementById('close-failure-modal');
  const restartButton = document.getElementById('restart-game');

  // Đóng cửa sổ bật lên
  function closeModal() {
    if (modal) {
      modal.classList.add('hidden');
      modal.style.display = 'none';
    }
  }

  // Gán sự kiện cho nút đóng
  if (closeButton) {
    closeButton.addEventListener('click', closeModal);
  }

  // Gán sự kiện cho nút tiếp tục chơi
  if (restartButton) {
    restartButton.addEventListener('click', function () {
      closeModal();
      // Gọi phương thức triggerQuickReply để gửi văn bản phục hồi trạng thái
      triggerQuickReply('Phục hồi giá trị sinh mệnh/thể lực, gỡ bỏ trang bị trên người, state="action_selection_mode" action="Trạng thái chờ chọn"');
    });
  }

  // Nhấp bên ngoài cửa sổ bật lên để đóng
  if (modal) {
    modal.addEventListener('click', e => {
      if (e.target === modal) {
        closeModal();
      }
    });
  }

  // Đóng bằng phím ESC
  document.addEventListener('keydown', e => {
    if (e.key === 'Escape' && !modal.classList.contains('hidden')) {
      closeModal();
    }
  });
}

