// Chức năng cửa sổ bật lên trợ giúp
function setupHelpPopup() {
  const helpButton = document.getElementById('help-button');
  const helpPopup = document.getElementById('help-popup');
  const closeButton = document.getElementById('close-help-popup');

  // Hiển thị cửa sổ bật lên trợ giúp
  function showHelpPopup() {
    console.log('Hiển thị cửa sổ bật lên trợ giúp');
    if (helpPopup) {
      helpPopup.classList.remove('hide');
      helpPopup.classList.add('show');
    }
  }

  // Ẩn cửa sổ bật lên trợ giúp
  function hideHelpPopup() {
    console.log('Ẩn cửa sổ bật lên trợ giúp');
    if (helpPopup) {
      helpPopup.classList.remove('show');
      helpPopup.classList.add('hide');
    }
  }

  // Gán sự kiện nhấp cho nút trợ giúp
  if (helpButton) {
    helpButton.addEventListener('click', function (e) {
      e.preventDefault();
      showHelpPopup();
    });
    console.log('Gán sự kiện cho nút trợ giúp thành công');
  } else {
    console.error('Không tìm thấy nút trợ giúp (help-button)');
  }

  // Gán sự kiện cho nút đóng
  if (closeButton) {
    closeButton.addEventListener('click', function (e) {
      e.preventDefault();
      hideHelpPopup();
    });
  } else {
    console.error('Không tìm thấy nút đóng (close-help-popup)');
  }

  // Nhấp bên ngoài cửa sổ bật lên để đóng (chức năng tùy chọn)
  document.addEventListener('click', function (e) {
    if (helpPopup && helpPopup.classList.contains('show')) {
      if (!helpPopup.contains(e.target) && !helpButton.contains(e.target)) {
        hideHelpPopup();
      }
    }
  });

  // Đóng bằng phím ESC
  document.addEventListener('keydown', function (e) {
    if (e.key === 'Escape' && helpPopup && helpPopup.classList.contains('show')) {
      hideHelpPopup();
    }
  });
}

// Chức năng lớp phủ hình ảnh
function setupImageZoomOverlay() {
  const overlay = document.getElementById('image-zoom-overlay');
  const zoomImage = document.getElementById('zoom-image');

  // Đóng lớp phủ
  function closeOverlay() {
    if (overlay) {
      overlay.classList.remove('show');
    }
  }

  // Hiển thị ảnh phóng to
  function showImage(imageSrc) {
    if (overlay && zoomImage) {
      zoomImage.src = imageSrc;
      overlay.classList.add('show');
    }
  }

  // Nhấp vào lớp phủ để đóng
  if (overlay) {
    overlay.addEventListener('click', closeOverlay);
  }

  // Đóng bằng phím ESC
  document.addEventListener('keydown', e => {
    if (e.key === 'Escape' && overlay.classList.contains('show')) {
      closeOverlay();
    }
  });

  // Trả về hàm hiển thị ảnh để mã khác gọi
  return { showImage };
}

// Chức năng cửa sổ bật lên cài đặt
function setupSettingsModal() {
  const modal = document.getElementById('settings-modal');
  const closeButton = document.getElementById('close-settings-modal');
  const openButton = document.getElementById('settings-button');

  // Đóng cửa sổ bật lên
  function closeModal() {
    if (modal) {
      modal.classList.add('hidden');
      modal.style.display = 'none';
    }
  }

  // Hiển thị cửa sổ bật lên
  function showModal() {
    if (modal) {
      modal.classList.remove('hidden');
      modal.style.display = 'flex';
    }
  }

  // Lưu cài đặt
  function saveSettings() {
    const settings = {
      themeMode: document.getElementById('theme-mode').value,
      smartCollapse: document.getElementById('smart-collapse').value,
    };

    // Lưu vào localStorage
    localStorage.setItem('gameSettings', JSON.stringify(settings));

    // Áp dụng cài đặt chủ đề
    applyTheme(settings.themeMode);

    console.log('Cài đặt đã được lưu:', settings);
  }



  // Áp dụng chủ đề
  function applyTheme(theme) {
    const body = document.body;

    // Xóa tất cả các lớp chủ đề
    body.classList.remove('dark-theme', 'horror-theme');

    // Áp dụng chủ đề mới
    if (theme === 'dark') {
      body.classList.add('dark-theme');
    } else if (theme === 'horror') {
      body.classList.add('horror-theme');
    }
    // Chủ đề sáng không cần thêm lớp, sử dụng kiểu mặc định
  }

  // Tải cài đặt đã lưu
  function loadSettings() {
    const savedSettings = localStorage.getItem('gameSettings');
    if (savedSettings) {
      try {
        const settings = JSON.parse(savedSettings);

        if (settings.themeMode !== undefined) {
          document.getElementById('theme-mode').value = settings.themeMode;
          applyTheme(settings.themeMode);
        }
        if (settings.smartCollapse !== undefined) {
          document.getElementById('smart-collapse').value = settings.smartCollapse;
        }
      } catch (e) {
        console.error('Tải cài đặt thất bại:', e);
      }
    } else {
      // Cài đặt mặc định
      applyTheme('light');
    }
  }

  // Gán sự kiện
  if (openButton) {
    openButton.addEventListener('click', showModal);
  }

  if (closeButton) {
    closeButton.addEventListener('click', closeModal);
  }

  // Xem trước và lưu thay đổi chủ đề theo thời gian thực
  const themeSelect = document.getElementById('theme-mode');
  if (themeSelect) {
    themeSelect.addEventListener('change', function () {
      applyTheme(this.value);
      // Lưu cài đặt chủ đề theo thời gian thực
      saveSettings();
    });
  }

  // Lưu cài đặt tự động thu gọn theo thời gian thực
  const smartCollapseSelect = document.getElementById('smart-collapse');
  if (smartCollapseSelect) {
    smartCollapseSelect.addEventListener('change', function () {
      // Lưu cài đặt theo thời gian thực
      saveSettings();
    });
  }

  // Nhấp bên ngoài cửa sổ bật lên để đóng
  if (modal) {
    modal.addEventListener('click', e => {
      if (e.target === modal) {
        closeModal();
      }
    });
  }

  // Đóng bằng phím ESC
  document.addEventListener('keydown', e => {
    if (e.key === 'Escape' && !modal.classList.contains('hidden')) {
      closeModal();
    }
  });

  // Tải cài đặt khi khởi tạo
  loadSettings();
}

// Chức năng nhấp vào ảnh đại diện
function setupAvatarClickEvents() {
  const playerAvatar = document.getElementById('player-avatar');
  const enemyAvatar = document.getElementById('enemy-avatar');

  // Sự kiện nhấp vào ảnh đại diện cá nhân
  if (playerAvatar) {
    playerAvatar.addEventListener('click', function () {
      // Trích xuất URL ảnh từ kiểu background-image
      const backgroundImage = window.getComputedStyle(playerAvatar).backgroundImage;
      let imageUrl = '';

      if (backgroundImage && backgroundImage !== 'none') {
        // Trích xuất đường dẫn trong URL url("path") -> path
        const match = backgroundImage.match(/url\(["']?([^"']*)["']?\)/);
        if (match && match[1] && !match[1].includes('{{userAvatarPath}}')) {
          imageUrl = match[1];
        }
      }

      if (imageUrl) {
        showFullscreenImage({ target: { src: imageUrl } });
      } else {
        // Nếu không có ảnh đại diện người chơi hợp lệ, hiển thị biểu tượng mặc định
        const defaultUserImage =
          'data:image/svg+xml;base64,';
        showFullscreenImage({ target: { src: defaultUserImage } });
      }
    });
  }

  // Sự kiện nhấp vào ảnh đại diện kẻ địch
  if (enemyAvatar) {
    enemyAvatar.addEventListener('click', function () {
      const enemyImage = document.getElementById('enemy-image');
      if (enemyImage && enemyImage.src) {
        showFullscreenImage({ target: { src: enemyImage.src } });
      }
    });
  }
}

// Triển khai chức năng di chuyển vị trí
document.addEventListener('DOMContentLoaded', function () {
  // Chức năng trả lời nhanh của SillyTavern
  const triggerQuickReply = (text) => {
    // Kiểm tra tính hợp lệ của văn bản, tránh gửi nội dung trống
    if (!text || ['…', '...'].includes(text.trim()) || text.trim().length === 0) return;

    // Thêm định dạng chỉ định vào sau tất cả văn bản được gửi
    const prefixedText = `${text}\n\n<action>\n(Phải xuất \${system_data})\n</action>`;

    // Kiểm tra môi trường SillyTavern và gửi lệnh
    if (typeof triggerSlash === 'function') {
      triggerSlash(`/send ${prefixedText}|/trigger`);
    } else {
      console.log('SillyTavern environment not detected. Would send:', prefixedText);
    }
  };

  // Đặt triggerQuickReply có thể truy cập toàn cục
  window.triggerQuickReply = triggerQuickReply;

  // Thêm trình lắng nghe ủy quyền sự kiện cho các tùy chọn hành động
  document.addEventListener('click', function(event) {
    const target = event.target;

    // Kiểm tra xem có nhấp vào nút tùy chọn chiến đấu không
    if (target.classList.contains('compact-battle-btn') ||
        target.classList.contains('compact-battle-continue-btn') ||
        target.classList.contains('compact-battle-run-btn')) {
      const text = target.textContent?.trim();
      if (text) {
        // Đối với nút chiến đấu, không gửi trực tiếp mà xử lý thông qua handleBattleAction
        // handleBattleAction sẽ gọi hệ thống chiến đấu và bao gồm dữ liệu battle_process

        // Trích xuất hành động thực tế từ văn bản của nút
        let action;
        if (text.includes('tấn công')) {
          action = 'Bắt đầu chiến đấu';
        } else if (text.includes('Tiếp tục chiến đấu') || text.includes('Muốn tôi dừng lại')) {
          action = 'Tiếp tục chiến đấu';
        } else if (text.includes('Chạy trốn') || text.includes('Đánh không lại')) {
          action = 'Chạy trốn';
        } else if (text.includes('chấp nhận') && text.includes('lời mời quan hệ')) {
          action = 'Chấp nhận lời mời quan hệ';
        } else if (text.includes('từ chối') && text.includes('đề nghị')) {
          action = 'Từ chối đề nghị quan hệ của cô ấy';
        } else {
          // Nếu là tùy chọn được tạo động, sử dụng văn bản gốc làm hành động trực tiếp
          action = text;
        }

        gameState.handleBattleAction(action);
      }
    }

    // Kiểm tra xem có nhấp vào nút tùy chọn tình dục không
    if (target.classList.contains('compact-sex-btn') || 
        target.classList.contains('compact-sex-continue-btn') ||
        target.classList.contains('compact-sex-end-btn')) {
      const text = target.textContent?.trim();
      if (text) {
        triggerQuickReply(text);
      }
    }

    // Kiểm tra xem có nhấp vào nút tùy chọn thanh toán chiến đấu không (không bao gồm nút chọn trang bị)
    if (target.classList.contains('settlement-action-btn')) {
      const text = target.textContent?.trim();
      if (text) {
        triggerQuickReply(text);
      }
    }

    // Nút chọn trang bị xóa sự kiện triggerQuickReply, chỉ xử lý thông qua sự kiện onclick
    // Việc xử lý các nút này hiện hoàn toàn do các phương thức gameState.takeDroppedEquipment và gameState.rejectDroppedEquipment chịu trách nhiệm

    // Kiểm tra xem có nhấp vào nút lựa chọn hành động không
    if (target.classList.contains('action-selection-btn')) {
      const action = target.getAttribute('data-action');
      const text = target.textContent?.trim();

      if (text) {
        triggerQuickReply(text);
      }

      if (action) {
        gameState.handleActionSelection(action);
      }
    }
  });

  // Hiển thị nội dung maintext
  renderMainText();

  // Khởi tạo trạng thái trò chơi - Đọc chế độ hiện tại từ nguồn dữ liệu
  gameState.initializeGameState();

  // Buộc cập nhật trạng thái hiển thị để đảm bảo hiển thị chính xác
  setTimeout(() => {
    console.log('Buộc cập nhật trạng thái hiển thị');
    gameState.updateOptionsDisplay();
  }, 100);

  // Cài đặt chức năng thu gọn bảng thông tin
  setupInfoPanelToggle();

  // Cài đặt chức năng chuyển đổi Tab
  setupTabSwitching();

  // Cài đặt chức năng hiển thị trạng thái hệ thống
  setupSystemStatusDisplay();

  // Cài đặt chức năng hiển thị thông tin người dùng
  setupUserInfoDisplay();

  // Cài đặt chức năng hiển thị thông tin kẻ địch
  setupEnemyInfoDisplay();

  // Cài đặt chức năng hiển thị quá trình chiến đấu
  setupBattleProcessDisplay();

  // Cài đặt chức năng bách khoa toàn thư kẻ địch
  setupEnemyCompendium();

  // Cài đặt chức năng bách khoa toàn thư vật phẩm
  setupItemCompendium();

  // Cài đặt cửa sổ bật lên khi thua game
  setupGameFailureModal();

  // Cài đặt cửa sổ bật lên khi thắng game
  setupGameVictoryModal();

  // Cài đặt cửa sổ bật lên trợ giúp
  setupHelpPopup();

  // Cài đặt lớp phủ hình ảnh
  setupImageZoomOverlay();

  // Cài đặt cửa sổ bật lên cài đặt
  setupSettingsModal();

  // Cài đặt sự kiện nhấp vào ảnh đại diện
  setupAvatarClickEvents();

  // Phân tích cú pháp dữ liệu JSON
  const jsonElement = document.getElementById('hospital_map');
  if (!jsonElement) {
    console.error('Không tìm thấy dữ liệu JSON có ID là hospital_map');
    return;
  }

  let hospitalData;
  try {
    const jsonData = JSON.parse(jsonElement.textContent);
    hospitalData = jsonData.hospital_map;
  } catch (e) {
    console.error('Phân tích cú pháp dữ liệu JSON thất bại:', e);
    return;
  }

  // Lấy các phần tử DOM
  const floorSelect = document.getElementById('floor-select');
  const areaSelect = document.getElementById('area-select');
  const enemyProbability = document.getElementById('enemy-probability');
  const probabilityText = document.getElementById('probability-text');
  const moveButton = document.getElementById('move-button');
  const storyContainer = document.querySelector('#tab-story-content .min-h-\\[300px\\]');

  // Lưu trữ dữ liệu khu vực được chọn hiện tại
  let currentFloorData = null;

  // Khởi tạo hộp chọn tầng
  function initFloorSelect() {
    // Xóa các tùy chọn hiện có
    floorSelect.innerHTML = '<option value="">Vui lòng chọn tầng</option>';

    // Thêm các tùy chọn tầng
    hospitalData.forEach((floor, index) => {
      const option = document.createElement('option');
      option.value = index;
      option.textContent = floor.floor;
      floorSelect.appendChild(option);
    });
  }

  // Cập nhật hộp chọn khu vực
  function updateAreaSelect(floorIndex) {
    // Xóa các tùy chọn hiện có và vô hiệu hóa
    areaSelect.innerHTML = '<option value="">Vui lòng chọn phòng</option>';
    areaSelect.disabled = true;

    // Ẩn xác suất gặp địch
    enemyProbability.style.display = 'none';
    moveButton.disabled = true;

    if (floorIndex === '' || !hospitalData[floorIndex]) return;

    // Lưu dữ liệu tầng hiện tại
    currentFloorData = hospitalData[floorIndex];

    // Định dạng JSON mới thống nhất sử dụng trường departments
    const areas = currentFloorData.departments || [];

    // Lấy thông tin phòng hiện tại
    let currentRoom = '';
    try {
      const systemDataYaml = getSystemDataFromXml();
      if (systemDataYaml) {
        const systemData = jsyaml.load(systemDataYaml);
        currentRoom = systemData.system_data?.system?.current_departments_name || '';
      }
    } catch (e) {
      console.warn('Không thể lấy thông tin phòng hiện tại:', e);
    }

    // Thêm các tùy chọn khu vực và kích hoạt hộp chọn
    if (areas.length > 0) {
      areas.forEach((area, index) => {
        const option = document.createElement('option');
        option.value = index;
        option.textContent = area.name;

        // Nếu là phòng hiện tại, thì làm mờ và đánh dấu
        if (area.name === currentRoom) {
          option.disabled = true;
          option.textContent = area.name + ' (Vị trí hiện tại)';
          option.style.color = '#9ca3af';
          option.style.fontStyle = 'italic';
        }

        areaSelect.appendChild(option);
      });
      areaSelect.disabled = false;
    }
  }

  // 更新遇敌概率显示
  function updateProbabilityDisplay(areaIndex) {
    if (!currentFloorData || areaIndex === '') {
      // Ẩn xác suất gặp địch và vô hiệu hóa nút di chuyển
      enemyProbability.style.display = 'none';
      moveButton.disabled = true;
      return;
    }

    // Định dạng JSON mới: lấy dữ liệu xác suất gặp địch của tầng hiện tại
    const enemyProbabilities = currentFloorData.enemy_probabilities || [];

    if (enemyProbabilities.length > 0) {
      // Định dạng văn bản xác suất gặp địch
      const formattedProbabilityText = enemyProbabilities
        .map(item => `${item.identity}：${item.probability}`)
        .join(' / ');

      // Hiển thị xác suất gặp địch và kích hoạt nút di chuyển
      document.getElementById('probability-text').textContent = formattedProbabilityText;
      enemyProbability.style.display = 'block';
      moveButton.disabled = false;
    } else {
      // Ẩn xác suất gặp địch và vô hiệu hóa nút di chuyển
      enemyProbability.style.display = 'none';
      moveButton.disabled = true;
    }
  }

  // Thực hiện hành động di chuyển
  function performMove() {
    if (!currentFloorData) return;

    const floorIndex = floorSelect.value;
    const areaIndex = areaSelect.value;

    if (floorIndex === '' || areaIndex === '') return;

    // Định dạng JSON mới: sử dụng trực tiếp mảng departments
    const area = currentFloorData.departments[areaIndex];

    // Lấy thông tin phòng hiện tại để xác thực
    let currentRoom = '';
    try {
      const systemDataYaml = getSystemDataFromXml();
      if (systemDataYaml) {
        const systemData = jsyaml.load(systemDataYaml);
        currentRoom = systemData.system_data?.system?.current_departments_name || '';
      }
    } catch (e) {
      console.warn('Không thể lấy thông tin phòng hiện tại:', e);
    }

    // Ngăn di chuyển đến phòng hiện tại
    if (area && area.name === currentRoom) {
      alert('Bạn đã ở trong phòng này rồi!');
      return;
    }

    if (area) {
      // Tạo câu mô tả di chuyển
      const moveDescription = `Tôi đã di chuyển đến ${currentFloorData.floor}，mở cửa phòng ${area.name}。`;

      // Gọi hệ thống xác suất gặp địch
      const encounterResult = generateRandomEncounter(currentFloorData.floor);

      // Xử lý định dạng kết quả gặp địch, đổi enemies_data thành random_enemies_data
      let formattedEncounterResult = '';
      if (encounterResult.includes('enemies_data:')) {
        formattedEncounterResult = encounterResult.replace('enemies_data:', 'random_enemies_data:');
      } else {
        formattedEncounterResult = encounterResult;
      }

      // Kiểm tra xem có hành động thanh toán chiến đấu đang chờ gửi không
      let finalMessage = '';
      if (gameState.pendingSettlementAction) {
        // Tin nhắn đầy đủ bao gồm hành động thanh toán chiến đấu và thông tin di chuyển
        finalMessage = `<action>\n1.${gameState.pendingSettlementAction}\n2.${moveDescription}\n</action>`;

        // Xóa hành động đang chờ gửi
        gameState.pendingSettlementAction = '';
        console.log('Gửi tin nhắn đầy đủ bao gồm hành động thanh toán chiến đấu và thông tin di chuyển');
      } else {
        // Chỉ có thông tin di chuyển
        finalMessage = moveDescription;
      }

      // Nối kết quả gặp địch vào sau tin nhắn cuối cùng
      finalMessage = `${finalMessage}\n${formattedEncounterResult}`;

      // Gọi triggerQuickReply để gửi tin nhắn
      triggerQuickReply(finalMessage);

      // Thêm thông tin di chuyển vào khu vực mô tả cốt truyện
      const moveInfo = document.createElement('p');
      moveInfo.className = 'mb-4';
      moveInfo.textContent = `Bạn đã di chuyển đến ${currentFloorData.floor} của ${area.name} 。${area.intro}`;

      // Thêm vào đầu khu vực cốt truyện
      // storyContainer.insertBefore(moveInfo, storyContainer.firstChild);

      // Cuộn lên đầu
      storyContainer.scrollTop = 0;
    }
  }

  // Gán trình lắng nghe sự kiện
  floorSelect.addEventListener('change', function () {
    updateAreaSelect(this.value);
  });

  areaSelect.addEventListener('change', function () {
    updateProbabilityDisplay(this.value);
  });

  moveButton.addEventListener('click', performMove);

  // Khởi tạo lựa chọn tầng
  initFloorSelect();
});

// Hệ thống chiến đấu theo lượt
function initiateTurnBasedBattle() {
  console.log('Bắt đầu chiến đấu theo lượt...');

  // Tạo số hiệp ngẫu nhiên từ 2-7
  const maxRounds = Math.floor(Math.random() * 6) + 2;
  console.log(`Trận chiến sẽ diễn ra trong ${maxRounds} hiệp`);

  // Đọc dữ liệu người dùng và kẻ địch từ system_data_xml
  const battleData = getBattleDataFromXml();
  if (!battleData) {
    console.error('Không thể lấy dữ liệu chiến đấu');
    return;
  }

  // Sao chép dữ liệu ban đầu (tránh sửa đổi dữ liệu gốc)
  let userStats = {
    name: battleData.user.name,
    health: parseHealthString(battleData.user.health),
    maxHealth: parseHealthString(battleData.user.health).max,
    attack: battleData.user.attack,
    defense: battleData.user.defense
  };

  let enemyStats = {
    name: battleData.enemy.name,
    health: parseHealthString(battleData.enemy.health),
    maxHealth: parseHealthString(battleData.enemy.health).max,
    attack: battleData.enemy.attack,
    defense: battleData.enemy.defense
  };

  console.log('Dữ liệu hai bên chiến đấu:', { userStats, enemyStats });

  // Khởi tạo nhật ký chiến đấu
  let battleProcess = [];
  let battleState = "Trạng thái đang chiến đấu";
  let currentRound = 1;
  let userFirst = true; // Hiệp đầu tiên người dùng tấn công trước

  // Bắt đầu vòng lặp chiến đấu
  while (currentRound <= maxRounds && userStats.health.current > 0 && enemyStats.health.current > 0) {
    console.log(`\n=== Hiệp ${currentRound} ===`);

    let roundLog = `round_${currentRound}: `;

    if (userFirst) {
      // Người dùng tấn công trước, kẻ địch phản công
      const userDamage = calculateDamage(userStats.attack, enemyStats.defense);
      enemyStats.health.current = Math.max(0, enemyStats.health.current - userDamage);

      let roundText = `${userStats.name} tấn công trước ${enemyStats.name} giá trị sinh mệnh-${userDamage}`;
      console.log(roundText);

      if (enemyStats.health.current > 0) {
        // Kẻ địch phản công
        const enemyDamage = calculateDamage(enemyStats.attack, userStats.defense);
        userStats.health.current = Math.max(0, userStats.health.current - enemyDamage);

        roundText += `, ${enemyStats.name} phản công,${userStats.name} giá trị sinh mệnh-${enemyDamage}`;
        console.log(`${enemyStats.name} phản công,${userStats.name} giá trị sinh mệnh-${enemyDamage}`);
      }

      roundLog += roundText;
    } else {
      // Kẻ địch tấn công trước, người dùng phản công
      const enemyDamage = calculateDamage(enemyStats.attack, userStats.defense);
      userStats.health.current = Math.max(0, userStats.health.current - enemyDamage);

      let roundText = `${enemyStats.name} tấn công trước ${userStats.name} giá trị sinh mệnh-${enemyDamage}`;
      console.log(roundText);

      if (userStats.health.current > 0) {
        // Người dùng phản công
        const userDamage = calculateDamage(userStats.attack, enemyStats.defense);
        enemyStats.health.current = Math.max(0, enemyStats.health.current - userDamage);

        roundText += `, ${userStats.name} phản công,${enemyStats.name} giá trị sinh mệnh-${userDamage}`;
        console.log(`${userStats.name} phản công,${enemyStats.name} giá trị sinh mệnh-${userDamage}`);
      }

      roundLog += roundText;
    }

    // Thêm vào nhật ký chiến đấu
    battleProcess.push(roundLog);

    // Kiểm tra xem trận chiến đã kết thúc chưa
    if (userStats.health.current <= 0) {
      console.log(`Giá trị sinh mệnh của ${userStats.name} về 0, trận chiến kết thúc！${enemyStats.name} chiến thắng！`);
      battleState = "Kết thúc chiến đấu";
      break;
    } else if (enemyStats.health.current <= 0) {
      console.log(`Giá trị sinh mệnh của ${enemyStats.name} về 0, trận chiến kết thúc！${userStats.name} chiến thắng！`);
      battleState = "Kết thúc chiến đấu";
      break;
    }

    // Thay đổi thứ tự tấn công trước
    userFirst = !userFirst;
    currentRound++;
  }

  // Nếu đã đạt đến số hiệp tối đa mà cả hai bên vẫn còn sống, trạng thái là tiếp tục chiến đấu
  if (currentRound > maxRounds && userStats.health.current > 0 && enemyStats.health.current > 0) {
    console.log('Đã đạt đến số hiệp tối đa, trạng thái đang chiến đấu, trạng thái đang chiến đấu');
    battleState = "Trạng thái đang chiến đấu";
  }

  // Cập nhật dữ liệu yaml của battle_process
  updateBattleProcessYaml(battleState, userStats, enemyStats, battleProcess);

  console.log('Trận chiến kết thúc, trạng thái cuối cùng:', {
    user: `${userStats.health.current}/${userStats.maxHealth}`,
    enemy: `${enemyStats.health.current}/${enemyStats.maxHealth}`,
    state: battleState
  });
}

// Lấy dữ liệu chiến đấu từ system_data_xml
function getBattleDataFromXml() {
  try {
    const systemDataYaml = getSystemDataFromXml();
    if (!systemDataYaml) {
      console.error('Không tìm thấy nguồn dữ liệu system_data_xml');
      return null;
    }

    const data = jsyaml.load(systemDataYaml);
    const systemData = data.system_data;

    if (!systemData || !systemData.user || !systemData.enemy) {
      console.error('Thiếu dữ liệu người dùng hoặc kẻ địch trong system_data');
      return null;
    }

    return {
      user: systemData.user,
      enemy: {
        name: systemData.enemy.name,
        health: systemData.enemy.stats.health,
        attack: systemData.enemy.stats.attack,
        defense: systemData.enemy.stats.defense
      }
    };
  } catch (e) {
    console.error('Phân tích cú pháp dữ liệu chiến đấu thất bại:', e);
    return null;
  }
}

// Phân tích cú pháp chuỗi giá trị sinh mệnh "10/10" -> {current: 10, max: 10}
function parseHealthString(healthStr) {
  const parts = healthStr.split('/');
  return {
    current: parseInt(parts[0]),
    max: parseInt(parts[1])
  };
}

// Tính toán sát thương: Lực tấn công - Lực phòng ngự = Giá trị sát thương (tối thiểu là 1)
function calculateDamage(attack, defense) {
  const damage = Math.max(1, attack - defense);
  return damage;
}

// Cập nhật dữ liệu YAML của battle_process
function updateBattleProcessYaml(battleState, userStats, enemyStats, battleProcess) {
  const battleProcessElement = document.getElementById('battle_process');
  if (!battleProcessElement) {
    console.error('Không tìm thấy phần tử battle_process');
    return;
  }

  // Xây dựng nội dung YAML mới
  const newYamlContent = `battle:
  state: "${battleState}"
  user:
    health: "${userStats.health.current}/${userStats.maxHealth}"
  enemy:
    health: "${enemyStats.health.current}/${enemyStats.maxHealth}"
  process:${battleProcess.map(log => `\n    - "${log}"`).join('')}`;

  // Cập nhật nội dung phần tử
  battleProcessElement.textContent = newYamlContent;

  console.log('battle_process đã được cập nhật:', newYamlContent);
}

// Lấy nội dung văn bản của battle_process và bọc bằng thẻ <battle>
function getBattleProcessText() {
  const battleProcessElement = document.getElementById('battle_process');
  if (!battleProcessElement) {
    console.error('Không tìm thấy phần tử battle_process');
    return '<battle>\nDữ liệu chiến đấu không khả dụng\n</battle>';
  }

  // Lấy nội dung văn bản của phần tử
  const yamlContent = battleProcessElement.textContent.trim();

  // Bọc bằng thẻ <battle>
  return `<battle>\n${yamlContent}\n</battle>`;
}



// Hệ thống xác suất gặp địch
function generateRandomEncounter(floorName) {
  try {
    console.log('Bắt đầu tạo kết quả gặp địch, tầng:', floorName);

    // Lấy dữ liệu hospital_map
    const hospitalMapElement = document.getElementById('hospital_map');
    if (!hospitalMapElement) {
      console.error('Không tìm thấy nguồn dữ liệu hospital_map');
      return "<action>Tôi đã cố gắng tìm kiếm ở đây, nhưng nơi này trống rỗng, không có gì cả.</action>";
    }

    const hospitalData = JSON.parse(hospitalMapElement.textContent);
    const floorData = hospitalData.hospital_map.find(floor => floor.floor === floorName);

    if (!floorData) {
      console.error('Không tìm thấy tầng được chỉ định:', floorName);
      return "<action>Tôi đã cố gắng tìm kiếm ở đây, nhưng nơi này trống rỗng, không có gì cả.</action>";
    }

    // Lấy dữ liệu enemies_data
    const enemiesDataElement = document.getElementById('enemies_data');
    if (!enemiesDataElement) {
      console.error('Không tìm thấy nguồn dữ liệu enemies_data');
      return "<action>Tôi đã cố gắng tìm kiếm ở đây, nhưng nơi này trống rỗng, không có gì cả.</action>";
    }

    const enemiesData = JSON.parse(enemiesDataElement.textContent);

    // Chọn ngẫu nhiên identity dựa trên xác suất
    const enemyProbabilities = floorData.enemy_probabilities || [];
    const selectedIdentity = selectRandomIdentity(enemyProbabilities);

    console.log('identity được chọn ngẫu nhiên:', selectedIdentity);

    // Nếu chọn "Không có kẻ địch", trả về kết quả rỗng
    if (selectedIdentity === 'Không có kẻ địch') {
      return "<action>Tôi đã cố gắng tìm kiếm ở đây, nhưng nơi này trống rỗng, không có gì cả.</action>";
    }

    // Lấy thông tin kẻ địch dựa trên identity
    const enemyTemplate = enemiesData.enemies_data.find(enemy => enemy.identity === selectedIdentity);
    if (!enemyTemplate) {
      console.error('Không tìm thấy mẫu kẻ địch:', selectedIdentity);
      return "<action>Tôi đã cố gắng tìm kiếm ở đây, nhưng nơi này trống rỗng, không có gì cả.</action>";
    }

    // Tạo ngẫu nhiên thuộc tính kẻ địch
    const randomEnemy = generateRandomEnemyStats(enemyTemplate);

    // Định dạng đầu ra
    const result = `<action>
   enemies_data:
     type: "${randomEnemy.type}"
     identity: "${randomEnemy.identity}"
     image: ${randomEnemy.image}
     health: ${randomEnemy.health}
     attack: ${randomEnemy.attack}
     defense: ${randomEnemy.defense}
</action>`;

    console.log('Kết quả gặp địch được tạo ra:', result);
    return result;

  } catch (e) {
    console.error('Tạo kết quả gặp địch thất bại:', e);
    return "<action>Tôi đã cố gắng tìm kiếm ở đây, nhưng nơi này trống rỗng, không có gì cả.</action>";
  }
}

// Chọn ngẫu nhiên identity dựa trên xác suất
function selectRandomIdentity(enemyProbabilities) {
  // Chuyển đổi xác suất thành giá trị số và cộng dồn
  let totalWeight = 0;
  const weights = enemyProbabilities.map(item => {
    const probability = parseFloat(item.probability.replace('%', ''));
    totalWeight += probability;
    return {
      identity: item.identity,
      weight: probability,
      cumulativeWeight: totalWeight
    };
  });

  // Tạo số ngẫu nhiên
  const random = Math.random() * totalWeight;

  // Chọn identity dựa trên trọng số tích lũy
  for (const item of weights) {
    if (random <= item.cumulativeWeight) {
      return item.identity;
    }
  }

  // Trả về phần tử đầu tiên làm phương án dự phòng
  return enemyProbabilities[0]?.identity || 'Không có kẻ địch';
}

// Tạo thuộc tính ngẫu nhiên dựa trên mẫu kẻ địch
function generateRandomEnemyStats(enemyTemplate) {
  // Tạo ngẫu nhiên giá trị thuộc tính
  const health = getRandomBetween(enemyTemplate.min_health, enemyTemplate.max_health);
  const attack = getRandomBetween(enemyTemplate.min_attack, enemyTemplate.max_attack);
  const defense = getRandomBetween(enemyTemplate.min_defense, enemyTemplate.max_defense);

  // Chọn ngẫu nhiên image
  const randomImageIndex = Math.floor(Math.random() * enemyTemplate.images.length);
  const selectedImage = enemyTemplate.images[randomImageIndex];

  return {
    type: enemyTemplate.type,
    identity: enemyTemplate.identity,
    image: selectedImage.image_id,
    health: health,
    attack: attack,
    defense: defense
  };
}

// Lấy số nguyên ngẫu nhiên trong một phạm vi được chỉ định
function getRandomBetween(min, max) {
  return Math.floor(Math.random() * (max - min + 1)) + min;
}

